#[tokio::main]
async fn main() -> anyhow::Result<()> {
    tracing_subscriber::fmt()
        .with_target(false)
        .compact()
        .init();

    let config = AppConfig::from_env();
    let addr: SocketAddr = config.bind_addr.parse()?;
    let service_name = config.service_name.clone();
    let catalog = build_catalog_store(config.database_url.as_deref()).await?;
    let bootstrap = build_bootstrap_store(
        config.bootstrap_state_path.clone(),
        config.database_url.as_deref(),
    );
    let local_sessions = try_build_local_session_store(
        config.local_session_state_path.clone(),
        config.database_url.as_deref(),
    )?;
    let browse = build_browse_store();
    let commits = build_commit_store();
    let search = build_search_store();
    let ask_threads = try_build_ask_thread_store(config.database_url.as_deref())?;

    let app = build_router(
        config,
        catalog,
        bootstrap,
        local_sessions,
        browse,
        commits,
        search,
        ask_threads,
    );

    info!(%addr, service = %service_name, "starting sourcebot api");

    let listener = tokio::net::TcpListener::bind(addr).await?;
    axum::serve(listener, app).await?;
    Ok(())
}

fn build_app_state(
    config: AppConfig,
    catalog: DynCatalogStore,
    bootstrap: DynBootstrapStore,
    local_sessions: DynLocalSessionStore,
    browse: DynBrowseStore,
    commits: DynCommitStore,
    search: DynSearchStore,
    ask_threads: DynAskThreadStore,
) -> AppState {
    let organization_store = build_organization_store(
        config.organization_state_path.clone(),
        config.database_url.as_deref(),
    );
    let organization_auth_metadata_store = config
        .database_url
        .as_deref()
        .map(PgOrganizationAuthMetadataStore::connect_lazy)
        .transpose()
        .expect("organization auth metadata DATABASE_URL must be valid when configured");

    AppState {
        config,
        catalog,
        bootstrap,
        local_sessions,
        organization_store,
        organization_auth_metadata_store,
        organization_state_write_lock: Arc::new(tokio::sync::Mutex::new(())),
        browse,
        commits,
        search,
        ask_threads,
    }
}

fn build_router(
    config: AppConfig,
    catalog: DynCatalogStore,
    bootstrap: DynBootstrapStore,
    local_sessions: DynLocalSessionStore,
    browse: DynBrowseStore,
    commits: DynCommitStore,
    search: DynSearchStore,
    ask_threads: DynAskThreadStore,
) -> Router {
    Router::new()
        .route("/healthz", get(healthz))
        .route("/readyz", get(readyz))
        .route("/api/v1/auth/worker-status", get(get_worker_status))
        .route(
            "/api/v1/auth/bootstrap",
            get(get_bootstrap_status).post(create_bootstrap_admin),
        )
        .route("/api/v1/auth/login", post(login_local_admin))
        .route("/api/v1/auth/invite-redeem", post(redeem_local_invite))
        .route("/api/v1/auth/me", get(get_authenticated_local_admin))
        .route(
            "/api/v1/auth/connections",
            get(list_authenticated_connections).post(create_authenticated_connection),
        )
        .route(
            "/api/v1/auth/connections/{connection_id}",
            put(update_authenticated_connection).delete(delete_authenticated_connection),
        )
        .route(
            "/api/v1/auth/repositories/import/local",
            post(import_authenticated_local_repository),
        )
        .route(
            "/api/v1/auth/api-keys",
            get(list_authenticated_api_keys).post(create_authenticated_api_key),
        )
        .route("/api/v1/auth/members", get(list_authenticated_members))
        .route(
            "/api/v1/auth/members/{user_id}",
            delete(remove_authenticated_member),
        )
        .route(
            "/api/v1/auth/members/{user_id}/role",
            patch(update_authenticated_member_role),
        )
        .route(
            "/api/v1/auth/members/invites",
            post(create_authenticated_members_invite),
        )
        .route(
            "/api/v1/auth/members/invites/{invite_id}",
            delete(cancel_authenticated_members_invite),
        )
        .route(
            "/api/v1/auth/linked-accounts",
            get(list_authenticated_linked_accounts),
        )
        .route(
            "/api/v1/auth/search-contexts",
            get(list_authenticated_search_contexts).post(create_authenticated_search_context),
        )
        .route(
            "/api/v1/auth/search-contexts/{context_id}",
            delete(delete_authenticated_search_context),
        )
        .route(
            "/api/v1/auth/repository-sync-jobs",
            get(list_authenticated_repository_sync_jobs)
                .post(create_authenticated_repository_sync_job),
        )
        .route(
            "/api/v1/auth/repository-sync-jobs/{job_id}/retry",
            post(retry_authenticated_repository_sync_job),
        )
        .route(
            "/api/v1/auth/audit-events",
            get(list_authenticated_audit_events),
        )
        .route("/api/v1/auth/analytics", get(list_authenticated_analytics))
        .route(
            "/api/v1/auth/review-webhooks",
            get(list_authenticated_review_webhooks).post(create_authenticated_review_webhook),
        )
        .route(
            "/api/v1/auth/review-webhooks/{webhook_id}",
            get(get_authenticated_review_webhook),
        )
        .route(
            "/api/v1/auth/review-webhooks/{webhook_id}/delivery-attempts",
            get(list_authenticated_review_webhook_delivery_attempts_for_webhook),
        )
        .route(
            "/api/v1/auth/review-webhooks/{webhook_id}/delivery-attempts/{attempt_id}",
            get(get_authenticated_review_webhook_delivery_attempt_for_webhook),
        )
        .route(
            "/api/v1/auth/review-webhooks/{webhook_id}/review-agent-runs",
            get(list_authenticated_review_agent_runs_for_webhook),
        )
        .route(
            "/api/v1/auth/review-webhooks/{webhook_id}/review-agent-runs/{run_id}",
            get(get_authenticated_review_agent_run_for_webhook),
        )
        .route(
            "/api/v1/auth/review-webhook-delivery-attempts",
            get(list_authenticated_review_webhook_delivery_attempts),
        )
        .route(
            "/api/v1/auth/review-webhook-delivery-attempts/{attempt_id}",
            get(get_authenticated_review_webhook_delivery_attempt),
        )
        .route(
            "/api/v1/auth/review-agent-runs",
            get(list_authenticated_review_agent_runs),
        )
        .route(
            "/api/v1/auth/review-agent-runs/{run_id}",
            get(get_authenticated_review_agent_run),
        )
        .route(
            "/api/v1/review-webhooks/{webhook_id}/events",
            post(intake_review_webhook_event),
        )
        .route(
            "/api/v1/auth/oauth-clients",
            get(list_authenticated_oauth_clients).post(create_authenticated_oauth_client),
        )
        .route(
            "/api/v1/auth/api-keys/{api_key_id}/revoke",
            post(revoke_authenticated_api_key),
        )
        .route("/api/v1/auth/logout", post(logout_local_admin))
        .route("/api/v1/auth/revoke", post(revoke_local_admin_session))
        .route("/api/v1/config", get(public_config))
        .route("/api/v1/mcp", post(handle_mcp_json_rpc))
        .route("/api/v1/mcp/manifest", get(get_mcp_manifest))
        .route("/api/v1/mcp/tools", get(list_mcp_tools))
        .route("/api/v1/mcp/tools/call", post(call_mcp_tool))
        .route("/api/v1/repos", get(list_repositories))
        .route("/api/v1/repos/{repo_id}", get(get_repository_detail))
        .route(
            "/api/v1/repos/{repo_id}/index-status",
            get(get_repository_index_status),
        )
        .route("/api/v1/repos/{repo_id}/tree", get(get_repository_tree))
        .route("/api/v1/repos/{repo_id}/blob", get(get_repository_blob))
        .route(
            "/api/v1/repos/{repo_id}/definitions",
            get(get_repository_definitions),
        )
        .route(
            "/api/v1/repos/{repo_id}/references",
            get(get_repository_references),
        )
        .route(
            "/api/v1/repos/{repo_id}/commits",
            get(list_repository_commits),
        )
        .route(
            "/api/v1/repos/{repo_id}/commits/{commit_id}",
            get(get_repository_commit),
        )
        .route(
            "/api/v1/repos/{repo_id}/commits/{commit_id}/diff",
            get(get_repository_commit_diff),
        )
        .route("/api/v1/search", get(search_repository_contents))
        .route("/api/v1/ask/completions", post(create_ask_completion))
        .route("/api/v1/ask/threads", get(list_ask_threads))
        .route(
            "/api/v1/ask/threads/{thread_id}",
            get(get_ask_thread)
                .patch(update_ask_thread)
                .delete(delete_ask_thread),
        )
        .with_state(build_app_state(
            config,
            catalog,
            bootstrap,
            local_sessions,
            browse,
            commits,
            search,
            ask_threads,
        ))
}

fn next_ask_entity_id(prefix: &str) -> String {
    let sequence = NEXT_ASK_ENTITY_ID.fetch_add(1, Ordering::Relaxed);
    format!("{prefix}_{sequence}")
}

fn current_timestamp() -> String {
    OffsetDateTime::now_utc()
        .format(&Rfc3339)
        .expect("current UTC time should format as RFC3339")
}

fn ask_thread_title_from_prompt(prompt: &str) -> String {
    const MAX_TITLE_CHARS: usize = 80;

    prompt.chars().take(MAX_TITLE_CHARS).collect()
}

fn organization_state_from_auth_metadata(
    metadata: OrganizationAuthMetadataState,
) -> OrganizationState {
    OrganizationState {
        organizations: metadata.organizations,
        accounts: metadata.accounts,
        external_accounts: metadata.external_accounts,
        memberships: metadata.memberships,
        invites: metadata.invites,
        repo_permissions: metadata.repo_permissions,
        ..OrganizationState::default()
    }
}

async fn local_account_by_email(
    state: &AppState,
    email: &str,
) -> Result<Option<LocalAccount>, StatusCode> {
    if let Some(store) = &state.organization_auth_metadata_store {
        return store
            .local_account_by_email(email)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR);
    }

    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    Ok(organization_state
        .accounts
        .iter()
        .find(|account| account.email.trim().eq_ignore_ascii_case(email))
        .cloned())
}

async fn local_account_by_id(
    state: &AppState,
    user_id: &str,
) -> Result<Option<LocalAccount>, StatusCode> {
    if let Some(store) = &state.organization_auth_metadata_store {
        return store
            .local_account_by_id(user_id)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR);
    }

    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    Ok(organization_state
        .accounts
        .iter()
        .find(|account| account.id == user_id)
        .cloned())
}

async fn admin_auth_organization_state(
    state: &AppState,
    user_id: &str,
) -> Result<OrganizationState, StatusCode> {
    if let Some(store) = &state.organization_auth_metadata_store {
        return store
            .admin_organization_auth_metadata(user_id)
            .await
            .map(organization_state_from_auth_metadata)
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR);
    }

    state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)
}

async fn user_auth_organization_state(
    state: &AppState,
    user_id: &str,
) -> Result<Option<OrganizationState>, StatusCode> {
    if let Some(store) = &state.organization_auth_metadata_store {
        return store
            .user_organization_auth_metadata(user_id)
            .await
            .map(|metadata| metadata.map(organization_state_from_auth_metadata))
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR);
    }

    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    if organization_state
        .accounts
        .iter()
        .any(|account| account.id == user_id)
    {
        Ok(Some(organization_state))
    } else {
        Ok(None)
    }
}

