async fn get_worker_status(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<WorkerStatusResponse>, StatusCode> {
    let _ = authenticate_local_session_record(&state, &headers).await?;
    Ok(Json(worker_status_response_for_path(
        state
            .config
            .worker_status_path
            .as_deref()
            .map(std::path::Path::new),
    )))
}

fn worker_status_response_for_path(path: Option<&std::path::Path>) -> WorkerStatusResponse {
    let Some(path) = path else {
        return WorkerStatusResponse {
            status: "not_configured",
            configured: false,
            snapshot: None,
            error: None,
        };
    };

    let metadata = match std::fs::metadata(path) {
        Ok(metadata) => metadata,
        Err(error) => {
            return WorkerStatusResponse {
                status: "error",
                configured: true,
                snapshot: None,
                error: Some(format!("worker status snapshot is not readable: {error}")),
            };
        }
    };
    if !metadata.is_file() {
        return WorkerStatusResponse {
            status: "error",
            configured: true,
            snapshot: None,
            error: Some("worker status snapshot path is not a file".into()),
        };
    }
    if metadata.len() > WORKER_STATUS_SNAPSHOT_MAX_BYTES {
        return WorkerStatusResponse {
            status: "error",
            configured: true,
            snapshot: None,
            error: Some("worker status snapshot exceeds the 64KiB read limit".into()),
        };
    }

    let snapshot_bytes = match std::fs::File::open(path).and_then(|file| {
        let mut bytes = Vec::new();
        file.take(WORKER_STATUS_SNAPSHOT_MAX_BYTES + 1)
            .read_to_end(&mut bytes)?;
        Ok(bytes)
    }) {
        Ok(bytes) if bytes.len() as u64 <= WORKER_STATUS_SNAPSHOT_MAX_BYTES => bytes,
        Ok(_) => {
            return WorkerStatusResponse {
                status: "error",
                configured: true,
                snapshot: None,
                error: Some("worker status snapshot exceeds the 64KiB read limit".into()),
            };
        }
        Err(error) => {
            return WorkerStatusResponse {
                status: "error",
                configured: true,
                snapshot: None,
                error: Some(format!("worker status snapshot is not readable: {error}")),
            };
        }
    };

    match serde_json::from_slice::<serde_json::Value>(&snapshot_bytes)
        .map_err(|error| std::io::Error::new(ErrorKind::InvalidData, error))
    {
        Ok(snapshot) => WorkerStatusResponse {
            status: "ok",
            configured: true,
            snapshot: Some(snapshot),
            error: None,
        },
        Err(error) => WorkerStatusResponse {
            status: "error",
            configured: true,
            snapshot: None,
            error: Some(format!("worker status snapshot is not valid JSON: {error}")),
        },
    }
}

async fn readyz(State(state): State<AppState>) -> (StatusCode, Json<ReadyResponse>) {
    let Some(database_url) = state.config.database_url.as_deref() else {
        return (
            StatusCode::OK,
            Json(ReadyResponse {
                status: "ok",
                service: state.config.service_name,
                metadata_backend: "file",
                database: None,
            }),
        );
    };

    match postgres_migration_count(database_url).await {
        Ok(applied_migrations) => (
            StatusCode::OK,
            Json(ReadyResponse {
                status: "ok",
                service: state.config.service_name,
                metadata_backend: "postgres",
                database: Some(ReadyDatabaseStatus {
                    status: "ok",
                    applied_migrations: Some(applied_migrations),
                    error: None,
                }),
            }),
        ),
        Err(error) => (
            StatusCode::SERVICE_UNAVAILABLE,
            Json(ReadyResponse {
                status: "degraded",
                service: state.config.service_name,
                metadata_backend: "postgres",
                database: Some(ReadyDatabaseStatus {
                    status: "error",
                    applied_migrations: None,
                    error: Some(error.to_string()),
                }),
            }),
        ),
    }
}

async fn postgres_migration_count(database_url: &str) -> anyhow::Result<i64> {
    tokio::time::timeout(Duration::from_secs(2), async {
        let pool = sqlx::postgres::PgPoolOptions::new()
            .max_connections(1)
            .connect(database_url)
            .await?;
        let count = sqlx::query_scalar::<_, i64>("SELECT COUNT(*) FROM _sqlx_migrations")
            .fetch_one(&pool)
            .await?;
        pool.close().await;
        Ok(count)
    })
    .await?
}

