async fn list_mcp_tools(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<Vec<sourcebot_mcp::McpToolDefinition>>, StatusCode> {
    let _ = search_request_context(&state, &headers).await?;
    Ok(Json(mcp_http_tool_definitions()))
}

fn mcp_http_tool_definitions() -> Vec<sourcebot_mcp::McpToolDefinition> {
    sourcebot_mcp::retrieval_tool_definitions()
        .into_iter()
        .map(|mut definition| {
            if definition.name != "list_repos" {
                if let Some(properties) = definition
                    .input_schema
                    .get_mut("properties")
                    .and_then(|properties| properties.as_object_mut())
                {
                    properties.insert(
                        "repo_id".into(),
                        serde_json::json!({
                            "type": "string",
                            "description": "Caller-visible repository id to use as the active MCP repository for this HTTP/API tool call"
                        }),
                    );
                }
                if let Some(schema) = definition.input_schema.as_object_mut() {
                    let required = schema
                        .entry("required")
                        .or_insert_with(|| serde_json::Value::Array(Vec::new()));
                    if let Some(required) = required.as_array_mut() {
                        if !required.iter().any(|value| value == "repo_id") {
                            required.push(serde_json::Value::String("repo_id".into()));
                        }
                    }
                }
            }
            definition
        })
        .collect()
}

fn bind_mcp_http_active_repo(
    request: &mut sourcebot_mcp::McpToolCallRequest,
    visible_repo_ids: &[String],
) -> Result<Option<String>, StatusCode> {
    let Some(arguments) = request.arguments.as_object_mut() else {
        return Ok(None);
    };
    let Some(repo_id) = arguments.remove("repo_id") else {
        return Ok(None);
    };
    let Some(repo_id) = repo_id
        .as_str()
        .map(str::trim)
        .filter(|repo_id| !repo_id.is_empty())
    else {
        return Err(StatusCode::BAD_REQUEST);
    };
    if !visible_repo_ids.iter().any(|visible| visible == repo_id) {
        return Err(StatusCode::NOT_FOUND);
    }
    Ok(Some(repo_id.to_string()))
}

fn bind_mcp_json_rpc_active_repo(
    request: &mut sourcebot_mcp::McpToolCallRequest,
) -> Result<Option<String>, StatusCode> {
    let Some(arguments) = request.arguments.as_object_mut() else {
        return Ok(None);
    };
    let Some(repo_id) = arguments.remove("repo_id") else {
        return Ok(None);
    };
    let Some(repo_id) = repo_id
        .as_str()
        .map(str::trim)
        .filter(|repo_id| !repo_id.is_empty())
    else {
        return Err(StatusCode::BAD_REQUEST);
    };
    Ok(Some(repo_id.to_string()))
}

async fn call_mcp_tool(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(mut request): Json<sourcebot_mcp::McpToolCallRequest>,
) -> Result<Json<sourcebot_mcp::McpToolCallResponse>, StatusCode> {
    let (_user_id, visible_repo_ids) = search_request_context(&state, &headers).await?;
    let mut visible_repo_ids = visible_repo_ids.into_iter().collect::<Vec<_>>();
    visible_repo_ids.sort();
    let response =
        execute_mcp_tool_call_for_visible_repos(&state, visible_repo_ids, &mut request).await?;

    Ok(Json(response))
}

async fn execute_mcp_tool_call_for_visible_repos(
    state: &AppState,
    visible_repo_ids: Vec<String>,
    request: &mut sourcebot_mcp::McpToolCallRequest,
) -> Result<sourcebot_mcp::McpToolCallResponse, StatusCode> {
    let active_repo_id = bind_mcp_http_active_repo(request, &visible_repo_ids)?;
    execute_mcp_tool_call_with_active_repo(state, visible_repo_ids, active_repo_id, request).await
}

async fn execute_mcp_json_rpc_tool_call_for_visible_repos(
    state: &AppState,
    visible_repo_ids: Vec<String>,
    request: &mut sourcebot_mcp::McpToolCallRequest,
) -> Result<sourcebot_mcp::McpToolCallResponse, StatusCode> {
    let active_repo_id = bind_mcp_json_rpc_active_repo(request)?;
    execute_mcp_tool_call_with_active_repo(state, visible_repo_ids, active_repo_id, request).await
}

async fn execute_mcp_tool_call_with_active_repo(
    state: &AppState,
    visible_repo_ids: Vec<String>,
    active_repo_id: Option<String>,
    request: &sourcebot_mcp::McpToolCallRequest,
) -> Result<sourcebot_mcp::McpToolCallResponse, StatusCode> {
    let context = RetrievalToolContext {
        active_repo_id,
        repo_scope: visible_repo_ids.clone(),
        visible_repo_ids,
    };

    let trees = BrowseTreeStoreAdapter::new(state.browse.clone());
    let blobs = BrowseBlobStoreAdapter::new(state.browse.clone());
    let globs = BrowseGlobStoreAdapter::new(state.browse.clone());
    let greps = BrowseGrepStoreAdapter::new(state.browse.clone());
    let response = sourcebot_mcp::execute_tool_call(
        state.catalog.as_ref(),
        &trees,
        &blobs,
        &globs,
        &greps,
        &context,
        request.clone(),
    )
    .await;

    Ok(response)
}

async fn handle_mcp_json_rpc(
    State(state): State<AppState>,
    headers: HeaderMap,
    body: Bytes,
) -> Result<Response, StatusCode> {
    let (_user_id, visible_repo_ids) = search_request_context(&state, &headers).await?;
    if !is_json_content_type(&headers) {
        return Err(StatusCode::UNSUPPORTED_MEDIA_TYPE);
    }
    if !accepts_json_response(&headers) {
        return Err(StatusCode::NOT_ACCEPTABLE);
    }
    let mut visible_repo_ids = visible_repo_ids.into_iter().collect::<Vec<_>>();
    visible_repo_ids.sort();
    let request = match serde_json::from_slice::<serde_json::Value>(&body) {
        Ok(request) => request,
        Err(error) => {
            return Ok(Json(mcp_json_rpc_error(
                serde_json::Value::Null,
                -32700,
                format!("parse error: {error}"),
            ))
            .into_response());
        }
    };

    if let Some(batch) = request.as_array() {
        if batch.is_empty() {
            return Ok(Json(mcp_json_rpc_error(
                serde_json::Value::Null,
                -32600,
                "invalid JSON-RPC batch: at least one request is required",
            ))
            .into_response());
        }

        let mut responses = Vec::new();
        for item in batch {
            if let Some(response) =
                process_mcp_json_rpc_request(&state, &visible_repo_ids, item.clone()).await?
            {
                responses.push(response);
            }
        }

        if responses.is_empty() {
            return Ok(StatusCode::NO_CONTENT.into_response());
        }

        return Ok(Json(serde_json::Value::Array(responses)).into_response());
    }

    let Some(response) = process_mcp_json_rpc_request(&state, &visible_repo_ids, request).await?
    else {
        return Ok(StatusCode::NO_CONTENT.into_response());
    };
    Ok(Json(response).into_response())
}

fn is_json_content_type(headers: &HeaderMap) -> bool {
    headers
        .get(header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .map(|value| {
            value
                .split(';')
                .next()
                .unwrap_or_default()
                .trim()
                .eq_ignore_ascii_case("application/json")
        })
        .unwrap_or(false)
}

fn accepts_json_response(headers: &HeaderMap) -> bool {
    let Some(accept) = headers
        .get(header::ACCEPT)
        .and_then(|value| value.to_str().ok())
    else {
        return true;
    };

    let mut exact_json_quality: Option<f32> = None;
    let mut application_wildcard_quality: Option<f32> = None;
    let mut any_wildcard_quality: Option<f32> = None;

    for item in accept.split(',') {
        let mut parts = item.split(';').map(str::trim);
        let media_type = parts.next().unwrap_or_default();
        let quality = accept_quality(parts);
        if media_type.eq_ignore_ascii_case("application/json") {
            exact_json_quality =
                Some(exact_json_quality.map_or(quality, |current| current.max(quality)));
        } else if media_type.eq_ignore_ascii_case("application/*") {
            application_wildcard_quality =
                Some(application_wildcard_quality.map_or(quality, |current| current.max(quality)));
        } else if media_type == "*/*" {
            any_wildcard_quality =
                Some(any_wildcard_quality.map_or(quality, |current| current.max(quality)));
        }
    }

    exact_json_quality
        .or(application_wildcard_quality)
        .or(any_wildcard_quality)
        .map(|quality| quality > 0.0)
        .unwrap_or(false)
}

fn accept_quality<'a>(parts: impl Iterator<Item = &'a str>) -> f32 {
    for part in parts {
        let Some((name, value)) = part.split_once('=') else {
            continue;
        };
        if name.trim().eq_ignore_ascii_case("q") {
            return value.trim().parse::<f32>().unwrap_or(1.0);
        }
    }
    1.0
}

fn is_json_rpc_id(id: &serde_json::Value) -> bool {
    matches!(
        id,
        serde_json::Value::Null | serde_json::Value::Number(_) | serde_json::Value::String(_)
    )
}

async fn process_mcp_json_rpc_request(
    state: &AppState,
    visible_repo_ids: &[String],
    request: serde_json::Value,
) -> Result<Option<serde_json::Value>, StatusCode> {
    if !request.is_object() {
        return Ok(Some(mcp_json_rpc_error(
            serde_json::Value::Null,
            -32600,
            "invalid JSON-RPC request: request must be an object",
        )));
    }

    let id = request
        .get("id")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let is_notification = request
        .as_object()
        .is_some_and(|request| !request.contains_key("id"));

    if !is_json_rpc_id(&id) {
        return Ok(Some(mcp_json_rpc_error(
            serde_json::Value::Null,
            -32600,
            "invalid JSON-RPC request: id must be a string, number, or null",
        )));
    }

    if request.get("jsonrpc") != Some(&serde_json::Value::String("2.0".into())) {
        if is_notification {
            return Ok(None);
        }
        return Ok(Some(mcp_json_rpc_error(
            id,
            -32600,
            "invalid JSON-RPC request: jsonrpc must be \"2.0\"",
        )));
    }

    let Some(method) = request.get("method").and_then(|method| method.as_str()) else {
        if is_notification {
            return Ok(None);
        }
        return Ok(Some(mcp_json_rpc_error(
            id,
            -32600,
            "invalid JSON-RPC request: method is required",
        )));
    };

    if is_notification {
        return Ok(None);
    }

    let result = match method {
        "initialize" => mcp_json_rpc_initialize_result(),
        "ping" => serde_json::json!({}),
        "notifications/initialized" => serde_json::json!({}),
        "tools/list" => serde_json::json!({
            "tools": mcp_json_rpc_tool_definitions(),
        }),
        "tools/call" => {
            let Some(params) = request.get("params") else {
                return Ok(Some(mcp_json_rpc_error(
                    id,
                    -32602,
                    "invalid params for tools/call: params object is required",
                )));
            };
            let mut tool_request: sourcebot_mcp::McpToolCallRequest =
                match serde_json::from_value(params.clone()) {
                    Ok(request) => request,
                    Err(_) => {
                        return Ok(Some(mcp_json_rpc_error(
                            id,
                            -32602,
                            "invalid params for tools/call: params must match MCP tool-call schema",
                        )));
                    }
                };
            let tool_response = match execute_mcp_json_rpc_tool_call_for_visible_repos(
                state,
                visible_repo_ids.to_vec(),
                &mut tool_request,
            )
            .await
            {
                Ok(response) => response,
                Err(StatusCode::BAD_REQUEST) => {
                    return Ok(Some(mcp_json_rpc_error(
                        id,
                        -32602,
                        "invalid params for tools/call: repo_id must be a non-empty string when provided",
                    )));
                }
                Err(status) => return Err(status),
            };
            mcp_json_rpc_tool_call_result(tool_response)
        }
        _ => {
            return Ok(Some(mcp_json_rpc_error(
                id,
                -32601,
                format!("method not found: {method}"),
            )));
        }
    };

    Ok(Some(serde_json::json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": result,
    })))
}

fn mcp_json_rpc_initialize_result() -> serde_json::Value {
    let manifest = sourcebot_mcp::server_manifest();
    serde_json::json!({
        "protocolVersion": manifest.protocol_version,
        "serverInfo": {
            "name": manifest.server_info.name,
            "version": manifest.server_info.version,
        },
        "capabilities": {
            "tools": {
                "listChanged": manifest.capabilities.tools.list_changed,
            }
        }
    })
}

fn mcp_json_rpc_tool_definitions() -> Vec<serde_json::Value> {
    mcp_http_tool_definitions()
        .into_iter()
        .map(|definition| {
            serde_json::json!({
                "name": definition.name,
                "description": definition.description,
                "inputSchema": definition.input_schema,
            })
        })
        .collect()
}

fn mcp_json_rpc_tool_call_result(
    response: sourcebot_mcp::McpToolCallResponse,
) -> serde_json::Value {
    match response {
        sourcebot_mcp::McpToolCallResponse::Success {
            structured_content, ..
        } => serde_json::json!({
            "content": [{
                "type": "text",
                "text": structured_content.to_string(),
            }],
            "structuredContent": structured_content,
            "isError": false,
        }),
        sourcebot_mcp::McpToolCallResponse::Error { error, .. } => {
            let code = error.code;
            let message = error.message;
            serde_json::json!({
                "content": [{
                    "type": "text",
                    "text": message,
                }],
                "structuredContent": {
                    "error": {
                        "code": code,
                        "message": message,
                    }
                },
                "isError": true,
            })
        }
    }
}

fn mcp_json_rpc_error(
    id: serde_json::Value,
    code: i64,
    message: impl Into<String>,
) -> serde_json::Value {
    serde_json::json!({
        "jsonrpc": "2.0",
        "id": id,
        "error": {
            "code": code,
            "message": message.into(),
        }
    })
}

