async fn create_authenticated_search_context(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(payload): Json<CreateSearchContextRequest>,
) -> Result<(StatusCode, Json<SearchContextListItemResponse>), StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let name = payload.name.trim().to_string();
    if name.is_empty() {
        return Err(StatusCode::BAD_REQUEST);
    }

    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let mut organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let visible_repo_ids: HashSet<String> =
        visible_repo_ids_for_user(&organization_state, &session.user_id)
            .into_iter()
            .collect();
    let timestamp = current_timestamp();
    let search_context = SearchContext {
        id: format!(
            "ctx_{}",
            SaltString::generate(&mut OsRng)
                .to_string()
                .chars()
                .filter(|ch| ch.is_ascii_alphanumeric())
                .collect::<String>()
        ),
        user_id: session.user_id,
        name,
        repo_scope: payload.repo_scope,
        created_at: timestamp.clone(),
        updated_at: timestamp,
    };
    let response = search_context_list_item_response(search_context.clone(), &visible_repo_ids);
    organization_state.search_contexts.push(search_context);
    state
        .organization_store
        .store_organization_state(organization_state)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok((StatusCode::CREATED, Json(response)))
}

async fn delete_authenticated_search_context(
    State(state): State<AppState>,
    Path(context_id): Path<String>,
    headers: HeaderMap,
) -> Result<StatusCode, StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let mut organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let Some(existing_context_index) =
        organization_state
            .search_contexts
            .iter()
            .position(|search_context| {
                search_context.id == context_id && search_context.user_id == session.user_id
            })
    else {
        return Err(StatusCode::NOT_FOUND);
    };

    organization_state
        .search_contexts
        .remove(existing_context_index);
    state
        .organization_store
        .store_organization_state(organization_state)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(StatusCode::NO_CONTENT)
}

async fn list_authenticated_audit_events(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<Vec<AuditEventListItemResponse>>, StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let auth_organization_state = user_auth_organization_state(&state, &session.user_id)
        .await?
        .ok_or(StatusCode::UNAUTHORIZED)?;
    let visible_organization_ids =
        visible_organization_ids_for_user(&auth_organization_state, &session.user_id);
    if let Some(store) = &state.organization_auth_metadata_store {
        let visible_organization_ids_vec =
            visible_organization_ids.iter().cloned().collect::<Vec<_>>();
        let mut audit_events = store
            .audit_events_for_organization_ids(&visible_organization_ids_vec)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
        if let Ok(compatibility_state) = state.organization_store.organization_state().await {
            audit_events.extend(compatibility_state.audit_events.into_iter().filter(
                |audit_event| visible_organization_ids.contains(&audit_event.organization_id),
            ));
        }
        audit_events.sort_by(|left, right| {
            right
                .occurred_at
                .cmp(&left.occurred_at)
                .then_with(|| right.id.cmp(&left.id))
        });
        return Ok(Json(
            audit_events
                .into_iter()
                .map(audit_event_list_item_response)
                .collect(),
        ));
    }

    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(
        organization_state
            .audit_events
            .into_iter()
            .filter(|audit_event| visible_organization_ids.contains(&audit_event.organization_id))
            .map(audit_event_list_item_response)
            .collect(),
    ))
}

async fn create_authenticated_repository_sync_job(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(payload): Json<CreateRepositorySyncJobRequest>,
) -> Result<(StatusCode, Json<RepositorySyncJobListItemResponse>), StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let organization_id = payload.organization_id.trim();
    let repository_id = payload.repository_id.trim();
    if organization_id.is_empty() || repository_id.is_empty() {
        return Err(StatusCode::BAD_REQUEST);
    }

    let visibility_state = user_auth_organization_state(&state, &session.user_id)
        .await?
        .ok_or(StatusCode::UNAUTHORIZED)?;
    if !user_is_organization_admin(&visibility_state, &session.user_id, organization_id) {
        return Err(StatusCode::NOT_FOUND);
    }
    let visible_repository_bindings =
        visible_repository_bindings_for_user(&visibility_state, &session.user_id);
    if !visible_repository_bindings
        .contains(&(organization_id.to_string(), repository_id.to_string()))
    {
        return Err(StatusCode::NOT_FOUND);
    }

    let repository_detail = state
        .catalog
        .get_repository_detail(repository_id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .ok_or(StatusCode::NOT_FOUND)?;

    let queued_at = OffsetDateTime::now_utc()
        .format(&Rfc3339)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let job = RepositorySyncJob {
        id: format!(
            "repo_sync_{}",
            SaltString::generate(&mut OsRng)
                .to_string()
                .chars()
                .filter(|ch| ch.is_ascii_alphanumeric())
                .collect::<String>()
        ),
        organization_id: organization_id.to_string(),
        repository_id: repository_id.to_string(),
        connection_id: repository_detail.repository.connection_id,
        status: sourcebot_models::RepositorySyncJobStatus::Queued,
        queued_at,
        started_at: None,
        finished_at: None,
        error: None,
        synced_revision: None,
        synced_branch: None,
        synced_content_file_count: None,
    };

    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let existing_job_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    if repository_sync_target_has_active_job(
        &existing_job_state,
        organization_id,
        repository_id,
        &job.connection_id,
    ) {
        return Err(StatusCode::CONFLICT);
    }
    state
        .organization_store
        .store_repository_sync_job(job.clone())
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok((
        StatusCode::CREATED,
        Json(repository_sync_job_list_item_response(job, false)),
    ))
}

async fn retry_authenticated_repository_sync_job(
    State(state): State<AppState>,
    Path(job_id): Path<String>,
    headers: HeaderMap,
) -> Result<(StatusCode, Json<RepositorySyncJobListItemResponse>), StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let requested_job_id = job_id.trim();
    if requested_job_id.is_empty() {
        return Err(StatusCode::BAD_REQUEST);
    }

    let visibility_state = user_auth_organization_state(&state, &session.user_id)
        .await?
        .ok_or(StatusCode::UNAUTHORIZED)?;
    let job_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let retry_source_job = job_state
        .repository_sync_jobs
        .iter()
        .find(|job| job.id == requested_job_id)
        .ok_or(StatusCode::NOT_FOUND)?;
    let visible_repository_bindings =
        visible_repository_bindings_for_user(&visibility_state, &session.user_id);
    if !visible_repository_bindings.contains(&(
        retry_source_job.organization_id.clone(),
        retry_source_job.repository_id.clone(),
    )) {
        return Err(StatusCode::NOT_FOUND);
    }
    if !user_is_organization_admin(
        &visibility_state,
        &session.user_id,
        &retry_source_job.organization_id,
    ) {
        return Err(StatusCode::FORBIDDEN);
    }
    if retry_source_job.status != sourcebot_models::RepositorySyncJobStatus::Failed {
        return Err(StatusCode::CONFLICT);
    }
    let retry_target_organization_id = retry_source_job.organization_id.clone();
    let retry_target_repository_id = retry_source_job.repository_id.clone();
    let retry_target_connection_id = retry_source_job.connection_id.clone();

    let queued_at = OffsetDateTime::now_utc()
        .format(&Rfc3339)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let retry_job = RepositorySyncJob {
        id: format!(
            "repo_sync_{}",
            SaltString::generate(&mut OsRng)
                .to_string()
                .chars()
                .filter(|ch| ch.is_ascii_alphanumeric())
                .collect::<String>()
        ),
        organization_id: retry_source_job.organization_id.clone(),
        repository_id: retry_source_job.repository_id.clone(),
        connection_id: retry_source_job.connection_id.clone(),
        status: sourcebot_models::RepositorySyncJobStatus::Queued,
        queued_at,
        started_at: None,
        finished_at: None,
        error: None,
        synced_revision: None,
        synced_branch: None,
        synced_content_file_count: None,
    };

    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let existing_job_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    if repository_sync_target_has_active_job(
        &existing_job_state,
        &retry_target_organization_id,
        &retry_target_repository_id,
        &retry_target_connection_id,
    ) {
        return Err(StatusCode::CONFLICT);
    }
    state
        .organization_store
        .store_repository_sync_job(retry_job.clone())
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok((
        StatusCode::CREATED,
        Json(repository_sync_job_list_item_response(retry_job, false)),
    ))
}

async fn list_authenticated_repository_sync_jobs(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<Vec<RepositorySyncJobListItemResponse>>, StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let job_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let visibility_state = user_auth_organization_state(&state, &session.user_id)
        .await?
        .ok_or(StatusCode::UNAUTHORIZED)?;
    let visible_organization_ids =
        visible_organization_ids_for_user(&visibility_state, &session.user_id);
    let visible_repository_bindings =
        visible_repository_bindings_for_user(&visibility_state, &session.user_id);
    let mut jobs: Vec<_> = job_state
        .repository_sync_jobs
        .into_iter()
        .filter(|job| {
            visible_organization_ids.contains(&job.organization_id)
                && visible_repository_bindings
                    .contains(&(job.organization_id.clone(), job.repository_id.clone()))
        })
        .collect();
    jobs.sort_by(|left, right| right.queued_at.cmp(&left.queued_at));

    Ok(Json(
        jobs.iter()
            .map(|job| {
                repository_sync_job_list_item_response(
                    job.clone(),
                    repository_sync_job_is_retryable_for_user(
                        job,
                        &jobs,
                        &visibility_state,
                        &session.user_id,
                    ),
                )
            })
            .collect(),
    ))
}

