async fn create_authenticated_oauth_client(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(payload): Json<CreateOAuthClientRequest>,
) -> Result<(StatusCode, Json<CreateOAuthClientResponse>), StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let mut organization_state = admin_auth_organization_state(&state, &session.user_id).await?;
    let visible_organization_ids =
        visible_organization_ids_for_user(&organization_state, &session.user_id);
    let organization_id = payload.organization_id.trim();
    let name = payload.name.trim();
    if organization_id.is_empty() || name.is_empty() {
        return Err(StatusCode::BAD_REQUEST);
    }
    if !visible_organization_ids.contains(organization_id)
        || !user_can_create_oauth_client(&organization_state, &session.user_id, organization_id)
    {
        return Err(StatusCode::NOT_FOUND);
    }

    let mut redirect_uris = Vec::with_capacity(payload.redirect_uris.len());
    for redirect_uri in payload.redirect_uris {
        let trimmed_redirect_uri = redirect_uri.trim();
        if trimmed_redirect_uri.is_empty() {
            return Err(StatusCode::BAD_REQUEST);
        }
        redirect_uris.push(trimmed_redirect_uri.to_string());
    }

    let id = format!(
        "oauth_client_{}",
        SaltString::generate(&mut OsRng)
            .to_string()
            .chars()
            .filter(|ch| ch.is_ascii_alphanumeric())
            .collect::<String>()
    );
    let client_id = format!(
        "oauth_client_id_{}",
        SaltString::generate(&mut OsRng)
            .to_string()
            .chars()
            .filter(|ch| ch.is_ascii_alphanumeric())
            .collect::<String>()
    );
    let client_secret = SaltString::generate(&mut OsRng).to_string();
    let client_secret_hash = Argon2::default()
        .hash_password(client_secret.as_bytes(), &SaltString::generate(&mut OsRng))
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .to_string();
    let created_at = current_timestamp();

    let client = OAuthClient {
        id: id.clone(),
        organization_id: organization_id.to_string(),
        name: name.to_string(),
        client_id: client_id.clone(),
        client_secret_hash,
        redirect_uris: redirect_uris.clone(),
        created_by_user_id: session.user_id.clone(),
        created_at: created_at.clone(),
        revoked_at: None,
    };
    let audit_metadata = serde_json::json!({
        "name": name,
        "redirect_uris": redirect_uris.clone(),
    });
    if let Some(store) = &state.organization_auth_metadata_store {
        store
            .create_oauth_client(client)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

        let mut persisted_organization_state =
            match state.organization_store.organization_state().await {
                Ok(state) => state,
                Err(_) => {
                    let _ = store.delete_oauth_client(&id, organization_id).await;
                    return Err(StatusCode::INTERNAL_SERVER_ERROR);
                }
            };
        append_oauth_client_audit_event(
            &mut persisted_organization_state,
            &session.user_id,
            organization_id,
            &id,
            &created_at,
            audit_metadata.clone(),
        );
        if let Err(_) = state
            .organization_store
            .store_organization_state(persisted_organization_state)
            .await
        {
            let _ = store.delete_oauth_client(&id, organization_id).await;
            return Err(StatusCode::INTERNAL_SERVER_ERROR);
        }
    } else {
        organization_state.oauth_clients.push(client);
        append_oauth_client_audit_event(
            &mut organization_state,
            &session.user_id,
            organization_id,
            &id,
            &created_at,
            audit_metadata,
        );
        state
            .organization_store
            .store_organization_state(organization_state)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    }

    Ok((
        StatusCode::CREATED,
        Json(CreateOAuthClientResponse {
            id,
            organization_id: organization_id.to_string(),
            name: name.to_string(),
            client_id,
            client_secret,
            redirect_uris,
            created_by_user_id: session.user_id,
            created_at,
            revoked_at: None,
        }),
    ))
}

async fn create_authenticated_review_webhook(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(payload): Json<CreateReviewWebhookRequest>,
) -> Result<(StatusCode, Json<CreateReviewWebhookResponse>), StatusCode> {
    let session = authenticate_local_session_record(&state, &headers).await?;
    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let mut organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let visible_organization_ids =
        visible_organization_ids_for_user(&organization_state, &session.user_id);
    let organization_id = payload.organization_id.trim();
    let connection_id = payload.connection_id.trim();
    let repository_id = payload.repository_id.trim();
    if organization_id.is_empty() || connection_id.is_empty() || repository_id.is_empty() {
        return Err(StatusCode::BAD_REQUEST);
    }
    if !visible_organization_ids.contains(organization_id)
        || !user_is_organization_admin(&organization_state, &session.user_id, organization_id)
    {
        return Err(StatusCode::NOT_FOUND);
    }

    let mut events = Vec::with_capacity(payload.events.len());
    for event in payload.events {
        let trimmed_event = event.trim();
        if trimmed_event.is_empty() || !is_supported_review_webhook_event(trimmed_event) {
            return Err(StatusCode::BAD_REQUEST);
        }
        events.push(trimmed_event.to_string());
    }

    let id = format!(
        "review_webhook_{}",
        SaltString::generate(&mut OsRng)
            .to_string()
            .chars()
            .filter(|ch| ch.is_ascii_alphanumeric())
            .collect::<String>()
    );
    let secret = SaltString::generate(&mut OsRng).to_string();
    let secret_hash = Argon2::default()
        .hash_password(secret.as_bytes(), &SaltString::generate(&mut OsRng))
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .to_string();
    let created_at = current_timestamp();

    organization_state.review_webhooks.push(ReviewWebhook {
        id: id.clone(),
        organization_id: organization_id.to_string(),
        connection_id: connection_id.to_string(),
        repository_id: repository_id.to_string(),
        events: events.clone(),
        secret_hash,
        created_by_user_id: session.user_id.clone(),
        created_at: created_at.clone(),
    });
    state
        .organization_store
        .store_organization_state(organization_state)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok((
        StatusCode::CREATED,
        Json(CreateReviewWebhookResponse {
            id,
            organization_id: organization_id.to_string(),
            connection_id: connection_id.to_string(),
            repository_id: repository_id.to_string(),
            events,
            secret,
            created_by_user_id: session.user_id,
            created_at,
        }),
    ))
}

async fn intake_review_webhook_event(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(webhook_id): Path<String>,
    Json(payload): Json<ReviewWebhookEventRequest>,
) -> Result<(StatusCode, Json<ReviewWebhookEventAckResponse>), StatusCode> {
    let (bearer_webhook_id, webhook_secret) = parse_bearer_token_id_secret(&headers)?;
    if bearer_webhook_id != webhook_id {
        return Err(StatusCode::UNAUTHORIZED);
    }

    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let webhook = if let Some(webhook) = organization_state
        .review_webhooks
        .iter()
        .find(|webhook| webhook.id == webhook_id)
        .cloned()
    {
        webhook
    } else {
        let _ = verify_secret_or_burn_failure(&webhook_secret, None);
        return Err(StatusCode::UNAUTHORIZED);
    };

    verify_review_webhook_secret(&webhook, &webhook_secret)?;

    let event_type = payload.event_type.trim();
    let connection_id = payload.connection_id.trim();
    let repository_id = payload.repository_id.trim();
    let review_id = payload.review_id.trim();
    let external_event_id = payload.external_event_id.trim();
    if event_type.is_empty()
        || connection_id.is_empty()
        || repository_id.is_empty()
        || review_id.is_empty()
        || external_event_id.is_empty()
    {
        return Err(StatusCode::BAD_REQUEST);
    }
    if !is_supported_review_webhook_event(event_type)
        || !webhook.events.iter().any(|event| event == event_type)
    {
        return Err(StatusCode::BAD_REQUEST);
    }
    if webhook.connection_id != connection_id || webhook.repository_id != repository_id {
        return Err(StatusCode::BAD_REQUEST);
    }

    let repository_detail = state
        .catalog
        .get_repository_detail(repository_id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .ok_or(StatusCode::BAD_REQUEST)?;
    if repository_detail.repository.connection_id != connection_id
        || repository_detail.connection.id != connection_id
    {
        return Err(StatusCode::BAD_REQUEST);
    }

    let _organization_state_write_guard = state.organization_state_write_lock.lock().await;
    let mut organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    organization_state
        .review_webhooks
        .iter()
        .find(|candidate| candidate.id == webhook_id)
        .filter(|candidate| {
            candidate.connection_id == webhook.connection_id
                && candidate.repository_id == webhook.repository_id
                && candidate.events == webhook.events
                && candidate.secret_hash == webhook.secret_hash
        })
        .ok_or(StatusCode::UNAUTHORIZED)?;

    let delivery_attempt_id = format!(
        "delivery_attempt_{}",
        SaltString::generate(&mut OsRng)
            .to_string()
            .chars()
            .filter(|ch| ch.is_ascii_alphanumeric())
            .collect::<String>()
    );
    organization_state
        .review_webhook_delivery_attempts
        .push(ReviewWebhookDeliveryAttempt {
            id: delivery_attempt_id.clone(),
            webhook_id: webhook.id.clone(),
            connection_id: connection_id.to_string(),
            repository_id: repository_id.to_string(),
            event_type: event_type.to_string(),
            review_id: review_id.to_string(),
            external_event_id: external_event_id.to_string(),
            accepted_at: current_timestamp(),
        });
    organization_state.review_agent_runs.push(ReviewAgentRun {
        id: format!(
            "review_agent_run_{}",
            SaltString::generate(&mut OsRng)
                .to_string()
                .chars()
                .filter(|ch| ch.is_ascii_alphanumeric())
                .collect::<String>()
        ),
        organization_id: webhook.organization_id.clone(),
        webhook_id: webhook.id.clone(),
        delivery_attempt_id,
        connection_id: connection_id.to_string(),
        repository_id: repository_id.to_string(),
        review_id: review_id.to_string(),
        status: ReviewAgentRunStatus::Queued,
        created_at: current_timestamp(),
    });
    state
        .organization_store
        .store_organization_state(organization_state)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok((
        StatusCode::ACCEPTED,
        Json(ReviewWebhookEventAckResponse {
            webhook_id,
            event_type: event_type.to_string(),
            accepted: true,
        }),
    ))
}

fn verify_review_webhook_secret(
    webhook: &ReviewWebhook,
    webhook_secret: &str,
) -> Result<(), StatusCode> {
    verify_secret_or_burn_failure(webhook_secret, Some(&webhook.secret_hash))
}

fn verify_secret_or_burn_failure(
    presented_secret: &str,
    persisted_hash: Option<&str>,
) -> Result<(), StatusCode> {
    if let Some(secret_hash) = persisted_hash.and_then(|hash| PasswordHash::new(hash).ok()) {
        return Argon2::default()
            .verify_password(presented_secret.as_bytes(), &secret_hash)
            .map_err(|_| StatusCode::UNAUTHORIZED);
    }

    burn_dummy_secret_verification_check(presented_secret);
    Err(StatusCode::UNAUTHORIZED)
}

fn burn_dummy_secret_verification_check(presented_secret: &str) {
    let dummy_salt = SaltString::encode_b64(b"credential-burn-dummy").expect("valid dummy salt");
    if let Ok(dummy_hash) = Argon2::default().hash_password(b"credential-burn-secret", &dummy_salt)
    {
        let _ = Argon2::default().verify_password(presented_secret.as_bytes(), &dummy_hash);
    }
}

fn is_supported_review_webhook_event(event: &str) -> bool {
    matches!(event, "pull_request" | "pull_request_review")
}

