async fn get_repository_definitions(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(repo_id): Path<String>,
    Query(query): Query<DefinitionsQuery>,
) -> Result<Json<DefinitionsResponse>, StatusCode> {
    let path = query
        .path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or(StatusCode::BAD_REQUEST)?;
    let symbol = query
        .symbol
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or(StatusCode::BAD_REQUEST)?;
    ensure_repo_visible_for_code_nav_request(&state, &headers, &repo_id).await?;
    let requested_revision = query
        .revision
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let effective_revision = requested_revision.as_deref().unwrap_or("HEAD");
    let response_revision = Some(effective_revision.to_string());

    let primary_blob = state
        .browse
        .get_blob_at_revision(&repo_id, path, Some(effective_revision))
        .map_err(map_browse_error_to_status)?;
    let blob = if let Some(blob) = primary_blob {
        blob
    } else if requested_revision.is_none() {
        if !headers.contains_key(header::AUTHORIZATION) {
            return Err(StatusCode::NOT_FOUND);
        }
        let (user_id, visible_repo_ids) = search_request_context(&state, &headers).await?;
        if !visible_repo_ids.contains(&repo_id) {
            return Err(StatusCode::NOT_FOUND);
        }
        let Some(snapshot_context) =
            local_sync_snapshot_browse_context_for_repo(&state, &user_id, &repo_id).await?
        else {
            return Err(StatusCode::NOT_FOUND);
        };
        let snapshot_revision = snapshot_context.revision.clone();
        let blob = snapshot_context
            .browse
            .get_blob_at_revision(&repo_id, path, None)
            .map_err(map_browse_error_to_status)?
            .ok_or(StatusCode::NOT_FOUND)?;
        return Ok(Json(build_definitions_response(
            repo_id,
            path,
            symbol,
            &snapshot_revision,
            blob,
        )));
    } else {
        return Err(StatusCode::NOT_FOUND);
    };

    let response = match extract_symbols(path, &blob.content) {
        sourcebot_search::SymbolExtraction::Supported { symbols } => {
            let definitions = symbols
                .into_iter()
                .filter(|candidate| candidate.name == symbol)
                .map(|candidate| DefinitionResponse {
                    browse_url: build_definition_browse_url(
                        &repo_id,
                        &candidate.path,
                        Some(effective_revision),
                        candidate.range.start_line,
                    ),
                    path: candidate.path,
                    name: candidate.name,
                    kind: candidate.kind,
                    range: DefinitionRangeResponse {
                        start_line: candidate.range.start_line,
                        end_line: candidate.range.end_line,
                    },
                })
                .collect();

            DefinitionsResponse::Supported {
                repo_id,
                path: path.to_string(),
                revision: response_revision,
                symbol: symbol.to_string(),
                definitions,
            }
        }
        sourcebot_search::SymbolExtraction::Unsupported { capability, .. } => {
            DefinitionsResponse::Unsupported {
                repo_id,
                path: path.to_string(),
                revision: response_revision,
                symbol: symbol.to_string(),
                capability,
                definitions: Vec::new(),
            }
        }
    };

    Ok(Json(response))
}

async fn get_repository_references(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(repo_id): Path<String>,
    Query(query): Query<ReferencesQuery>,
) -> Result<Json<ReferencesResponse>, StatusCode> {
    let path = query
        .path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or(StatusCode::BAD_REQUEST)?;
    let symbol = query
        .symbol
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or(StatusCode::BAD_REQUEST)?;
    ensure_repo_visible_for_code_nav_request(&state, &headers, &repo_id).await?;
    let requested_revision = query
        .revision
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned);
    let effective_revision = requested_revision.as_deref().unwrap_or("HEAD");
    let response_revision = Some(effective_revision.to_string());

    let primary_blob = state
        .browse
        .get_blob_at_revision(&repo_id, path, Some(effective_revision))
        .map_err(map_browse_error_to_status)?;

    let response = if let Some(blob) = primary_blob {
        match extract_symbols(path, &blob.content) {
            sourcebot_search::SymbolExtraction::Supported { .. } => {
                let references = state
                    .browse
                    .find_text_references_at_revision(&repo_id, symbol, effective_revision)
                    .map_err(map_browse_error_to_status)?
                    .ok_or(StatusCode::NOT_FOUND)?;
                let references =
                    build_reference_responses(&repo_id, Some(effective_revision), references);

                ReferencesResponse::Supported {
                    repo_id,
                    path: path.to_string(),
                    revision: response_revision.clone(),
                    symbol: symbol.to_string(),
                    references,
                }
            }
            sourcebot_search::SymbolExtraction::Unsupported { capability, .. } => {
                ReferencesResponse::Unsupported {
                    repo_id,
                    path: path.to_string(),
                    revision: response_revision,
                    symbol: symbol.to_string(),
                    capability,
                    references: Vec::new(),
                }
            }
        }
    } else if requested_revision.is_none() {
        if !headers.contains_key(header::AUTHORIZATION) {
            return Err(StatusCode::NOT_FOUND);
        }
        let (user_id, visible_repo_ids) = search_request_context(&state, &headers).await?;
        if !visible_repo_ids.contains(&repo_id) {
            return Err(StatusCode::NOT_FOUND);
        }
        let Some(snapshot_context) =
            local_sync_snapshot_browse_context_for_repo(&state, &user_id, &repo_id).await?
        else {
            return Err(StatusCode::NOT_FOUND);
        };
        let snapshot_revision = snapshot_context.revision.clone();
        let blob = snapshot_context
            .browse
            .get_blob_at_revision(&repo_id, path, None)
            .map_err(map_browse_error_to_status)?
            .ok_or(StatusCode::NOT_FOUND)?;
        match extract_symbols(path, &blob.content) {
            sourcebot_search::SymbolExtraction::Supported { .. } => {
                let references = snapshot_context
                    .browse
                    .grep(&repo_id, symbol)
                    .map_err(map_browse_error_to_status)?
                    .ok_or(StatusCode::NOT_FOUND)?
                    .matches
                    .into_iter()
                    .map(|hit| ReferenceMatch {
                        path: hit.path,
                        line_number: hit.line_number,
                        line: hit.line,
                    })
                    .collect();
                let references =
                    build_reference_responses(&repo_id, Some(&snapshot_revision), references);

                ReferencesResponse::Supported {
                    repo_id,
                    path: path.to_string(),
                    revision: Some(snapshot_revision),
                    symbol: symbol.to_string(),
                    references,
                }
            }
            sourcebot_search::SymbolExtraction::Unsupported { capability, .. } => {
                ReferencesResponse::Unsupported {
                    repo_id,
                    path: path.to_string(),
                    revision: Some(snapshot_revision),
                    symbol: symbol.to_string(),
                    capability,
                    references: Vec::new(),
                }
            }
        }
    } else {
        return Err(StatusCode::NOT_FOUND);
    };

    Ok(Json(response))
}

fn build_definitions_response(
    repo_id: String,
    path: &str,
    symbol: &str,
    revision: &str,
    blob: BlobResponse,
) -> DefinitionsResponse {
    match extract_symbols(path, &blob.content) {
        sourcebot_search::SymbolExtraction::Supported { symbols } => {
            let definitions = symbols
                .into_iter()
                .filter(|candidate| candidate.name == symbol)
                .map(|candidate| DefinitionResponse {
                    browse_url: build_definition_browse_url(
                        &repo_id,
                        &candidate.path,
                        Some(revision),
                        candidate.range.start_line,
                    ),
                    path: candidate.path,
                    name: candidate.name,
                    kind: candidate.kind,
                    range: DefinitionRangeResponse {
                        start_line: candidate.range.start_line,
                        end_line: candidate.range.end_line,
                    },
                })
                .collect();

            DefinitionsResponse::Supported {
                repo_id,
                path: path.to_string(),
                revision: Some(revision.to_string()),
                symbol: symbol.to_string(),
                definitions,
            }
        }
        sourcebot_search::SymbolExtraction::Unsupported { capability, .. } => {
            DefinitionsResponse::Unsupported {
                repo_id,
                path: path.to_string(),
                revision: Some(revision.to_string()),
                symbol: symbol.to_string(),
                capability,
                definitions: Vec::new(),
            }
        }
    }
}

fn build_definition_browse_url(
    repo_id: &str,
    path: &str,
    revision: Option<&str>,
    start_line: usize,
) -> String {
    build_blob_browse_url(repo_id, path, revision, start_line)
}

fn build_reference_browse_url(
    repo_id: &str,
    path: &str,
    revision: Option<&str>,
    line_number: usize,
) -> String {
    build_blob_browse_url(repo_id, path, revision, line_number)
}

fn build_blob_browse_url(
    repo_id: &str,
    path: &str,
    revision: Option<&str>,
    line_number: usize,
) -> String {
    let encoded_repo_id = encode_query_value(repo_id);
    let encoded_path = encode_query_value(path);
    let revision_suffix = revision
        .map(|revision| format!("&revision={}", encode_query_value(revision)))
        .unwrap_or_default();
    format!(
        "/api/v1/repos/{encoded_repo_id}/blob?path={encoded_path}{revision_suffix}#L{line_number}"
    )
}

fn build_reference_responses(
    repo_id: &str,
    revision: Option<&str>,
    references: Vec<ReferenceMatch>,
) -> Vec<ReferenceResponse> {
    let mut references = references
        .into_iter()
        .map(|reference| ReferenceResponse {
            browse_url: build_reference_browse_url(
                repo_id,
                &reference.path,
                revision,
                reference.line_number,
            ),
            path: reference.path,
            line_number: reference.line_number,
            line: reference.line,
        })
        .collect::<Vec<_>>();

    references.sort_by(|left, right| {
        left.path
            .cmp(&right.path)
            .then(left.line_number.cmp(&right.line_number))
            .then(left.line.cmp(&right.line))
            .then(left.browse_url.cmp(&right.browse_url))
    });
    references.dedup();
    references.truncate(MAX_CODE_NAV_REFERENCE_RESULTS);
    references
}

fn encode_query_value(value: &str) -> String {
    let mut encoded = String::new();
    for byte in value.bytes() {
        match byte {
            b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9' | b'-' | b'.' | b'_' | b'~' => {
                encoded.push(byte as char);
            }
            _ => encoded.push_str(&format!("%{:02X}", byte)),
        }
    }
    encoded
}

fn map_browse_error_to_status(error: anyhow::Error) -> StatusCode {
    if error.to_string().contains("invalid relative path") {
        StatusCode::BAD_REQUEST
    } else {
        StatusCode::NOT_FOUND
    }
}

async fn list_repository_commits(
    State(state): State<AppState>,
    Path(repo_id): Path<String>,
    Query(query): Query<CommitListQuery>,
    headers: HeaderMap,
) -> Result<Json<CommitListResponse>, StatusCode> {
    let revision = query
        .revision
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());

    let commits = if let Some(commits) = state
        .commits
        .list_commits(&repo_id, query.limit, query.offset, revision)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
    {
        commits
    } else if revision.is_none() {
        if let Some(store) = local_sync_commit_store_for_repo(&state, &headers, &repo_id).await? {
            store
                .list_commits(&repo_id, query.limit, query.offset, revision)
                .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
                .ok_or(StatusCode::NOT_FOUND)?
        } else {
            return Err(StatusCode::NOT_FOUND);
        }
    } else {
        return Err(StatusCode::NOT_FOUND);
    };

    Ok(Json(commits))
}

