async fn local_sync_commit_store_for_repo(
    state: &AppState,
    headers: &HeaderMap,
    repo_id: &str,
) -> Result<Option<LocalCommitStore>, StatusCode> {
    if headers.get(header::AUTHORIZATION).is_none() {
        return Ok(None);
    }

    let (user_id, visible_repo_ids) = search_request_context(state, headers).await?;
    if !visible_repo_ids.contains(repo_id) {
        return Ok(None);
    }

    let organization_state = user_auth_organization_state(state, &user_id)
        .await?
        .ok_or(StatusCode::UNAUTHORIZED)?;
    let authorized_organization_ids =
        authorized_organization_ids_for_repo(&organization_state, &user_id, repo_id);
    let Some(snapshot) =
        latest_local_sync_snapshot(&organization_state, repo_id, &authorized_organization_ids)
    else {
        return Ok(None);
    };

    Ok(Some(LocalCommitStore::new(HashMap::from([(
        repo_id.to_string(),
        snapshot.repo_root,
    )]))))
}

async fn visible_repo_ids_for_user_id(
    state: &AppState,
    user_id: &str,
) -> Result<HashSet<String>, StatusCode> {
    let organization_state = user_auth_organization_state(state, user_id)
        .await?
        .ok_or(StatusCode::UNAUTHORIZED)?;

    Ok(visible_repo_ids_for_user(&organization_state, user_id)
        .into_iter()
        .collect())
}

async fn visible_repo_ids_for_request(
    state: &AppState,
    headers: &HeaderMap,
) -> Result<HashSet<String>, StatusCode> {
    let session = authenticate_local_session_record(state, headers).await?;
    visible_repo_ids_for_user_id(state, &session.user_id).await
}

async fn search_request_context(
    state: &AppState,
    headers: &HeaderMap,
) -> Result<(String, HashSet<String>), StatusCode> {
    match authenticate_api_key_record(state, headers).await {
        Ok(authenticated_api_key) => {
            let visible_repo_ids =
                visible_repo_ids_for_user_id(state, &authenticated_api_key.user_id).await?;
            let scoped_visible_repo_ids = if authenticated_api_key.repo_scope.is_empty() {
                visible_repo_ids
            } else {
                authenticated_api_key
                    .repo_scope
                    .into_iter()
                    .filter(|repo_id| visible_repo_ids.contains(repo_id))
                    .collect()
            };

            Ok((authenticated_api_key.user_id, scoped_visible_repo_ids))
        }
        Err(StatusCode::UNAUTHORIZED) => {
            let session = authenticate_local_session_record(state, headers).await?;
            let visible_repo_ids = visible_repo_ids_for_user_id(state, &session.user_id).await?;
            Ok((session.user_id, visible_repo_ids))
        }
        Err(status) => Err(status),
    }
}

async fn visible_search_repo_ids_for_request(
    state: &AppState,
    headers: &HeaderMap,
) -> Result<HashSet<String>, StatusCode> {
    let (_user_id, visible_repo_ids) = search_request_context(state, headers).await?;
    Ok(visible_repo_ids)
}

async fn visible_browse_repo_ids_for_request(
    state: &AppState,
    headers: &HeaderMap,
) -> Result<HashSet<String>, StatusCode> {
    match authenticate_api_key_record(state, headers).await {
        Ok(authenticated_api_key) => {
            let visible_repo_ids =
                visible_repo_ids_for_user_id(state, &authenticated_api_key.user_id).await?;
            if authenticated_api_key.repo_scope.is_empty() {
                return Ok(visible_repo_ids);
            }

            Ok(authenticated_api_key
                .repo_scope
                .into_iter()
                .filter(|repo_id| visible_repo_ids.contains(repo_id))
                .collect())
        }
        Err(StatusCode::UNAUTHORIZED) => visible_repo_ids_for_request(state, headers).await,
        Err(status) => Err(status),
    }
}

async fn ask_request_context(
    state: &AppState,
    headers: &HeaderMap,
) -> Result<(String, HashSet<String>), StatusCode> {
    match authenticate_api_key_record(state, headers).await {
        Ok(authenticated_api_key) => {
            let visible_repo_ids =
                visible_repo_ids_for_user_id(state, &authenticated_api_key.user_id).await?;
            let scoped_visible_repo_ids = if authenticated_api_key.repo_scope.is_empty() {
                visible_repo_ids
            } else {
                authenticated_api_key
                    .repo_scope
                    .into_iter()
                    .filter(|repo_id| visible_repo_ids.contains(repo_id))
                    .collect()
            };

            Ok((authenticated_api_key.user_id, scoped_visible_repo_ids))
        }
        Err(StatusCode::UNAUTHORIZED) => {
            let session = authenticate_local_session_record(state, headers).await?;
            let visible_repo_ids = visible_repo_ids_for_user_id(state, &session.user_id).await?;
            Ok((session.user_id, visible_repo_ids))
        }
        Err(status) => Err(status),
    }
}

async fn ensure_repo_visible_for_request(
    state: &AppState,
    headers: &HeaderMap,
    repo_id: &str,
) -> Result<(), StatusCode> {
    let visible_repo_ids = visible_browse_repo_ids_for_request(state, headers).await?;
    if !visible_repo_ids.contains(repo_id) {
        return Err(StatusCode::NOT_FOUND);
    }

    Ok(())
}

async fn ensure_repo_visible_for_code_nav_request(
    state: &AppState,
    headers: &HeaderMap,
    repo_id: &str,
) -> Result<(), StatusCode> {
    if headers.contains_key(header::AUTHORIZATION) {
        ensure_repo_visible_for_request(state, headers, repo_id).await?;
    }

    Ok(())
}

async fn get_repository_index_status(
    State(state): State<AppState>,
    headers: HeaderMap,
    Path(repo_id): Path<String>,
) -> Result<Json<RepositoryIndexStatus>, StatusCode> {
    ensure_repo_visible_for_request(&state, &headers, &repo_id).await?;
    if let Some(status) = state
        .search
        .repository_index_status(&repo_id)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
    {
        return Ok(Json(status));
    }

    let (user_id, _) = search_request_context(&state, &headers).await?;
    let status = local_sync_snapshot_index_status_for_repo(&state, &user_id, &repo_id)
        .await?
        .ok_or(StatusCode::NOT_FOUND)?;
    Ok(Json(status))
}

struct LocalSyncSnapshotBrowseContext {
    browse: LocalBrowseStore,
    revision: String,
}

async fn local_sync_snapshot_browse_store_for_repo(
    state: &AppState,
    user_id: &str,
    repo_id: &str,
) -> Result<Option<LocalBrowseStore>, StatusCode> {
    Ok(
        local_sync_snapshot_browse_context_for_repo(state, user_id, repo_id)
            .await?
            .map(|context| context.browse),
    )
}

async fn local_sync_snapshot_browse_context_for_repo(
    state: &AppState,
    user_id: &str,
    repo_id: &str,
) -> Result<Option<LocalSyncSnapshotBrowseContext>, StatusCode> {
    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let authorized_organization_ids =
        authorized_organization_ids_for_repo(&organization_state, user_id, repo_id);
    if authorized_organization_ids.is_empty() {
        return Ok(None);
    }
    let Some(snapshot) =
        latest_local_sync_snapshot(&organization_state, repo_id, &authorized_organization_ids)
    else {
        return Ok(None);
    };
    if !snapshot.path.is_dir() {
        return Ok(None);
    }

    Ok(Some(LocalSyncSnapshotBrowseContext {
        browse: LocalBrowseStore::new(HashMap::from([(repo_id.to_string(), snapshot.path)])),
        revision: snapshot.revision,
    }))
}

async fn local_sync_snapshot_index_status_for_repo(
    state: &AppState,
    user_id: &str,
    repo_id: &str,
) -> Result<Option<RepositoryIndexStatus>, StatusCode> {
    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let authorized_organization_ids =
        authorized_organization_ids_for_repo(&organization_state, user_id, repo_id);
    if authorized_organization_ids.is_empty() {
        return Ok(None);
    }
    let Some(snapshot) =
        latest_local_sync_snapshot(&organization_state, repo_id, &authorized_organization_ids)
    else {
        return Ok(None);
    };
    match std::fs::symlink_metadata(&snapshot.search_index_artifact_path) {
        Ok(metadata) => {
            if !metadata.is_file() {
                return Ok(Some(malformed_search_index_artifact_status(
                    repo_id,
                    &snapshot.search_index_artifact_path,
                    anyhow::anyhow!(
                        "search index artifact is not a regular file: {}",
                        snapshot.search_index_artifact_path.display()
                    ),
                )));
            }
            return match LocalSearchStore::from_index_artifact(
                repo_id,
                &snapshot.search_index_artifact_path,
            )
            .and_then(|search| search.repository_index_status(repo_id))
            {
                Ok(status) => Ok(status),
                Err(error) => Ok(Some(malformed_search_index_artifact_status(
                    repo_id,
                    &snapshot.search_index_artifact_path,
                    error,
                ))),
            };
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
        Err(_) => return Err(StatusCode::INTERNAL_SERVER_ERROR),
    }
    if !snapshot.path.is_dir() {
        return Ok(None);
    }

    let snapshot_search =
        LocalSearchStore::new(HashMap::from([(repo_id.to_string(), snapshot.path)]));
    snapshot_search
        .repository_index_status(repo_id)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)
}

fn malformed_search_index_artifact_status(
    repo_id: &str,
    artifact_path: &std::path::Path,
    error: anyhow::Error,
) -> RepositoryIndexStatus {
    let artifact_path = artifact_path.display().to_string();
    let mut error = error.to_string();
    if !artifact_path.is_empty() {
        error = error.replace(&artifact_path, "<redacted>");
    }

    RepositoryIndexStatus {
        repo_id: repo_id.to_string(),
        status: RepositoryIndexState::Error,
        indexed_file_count: 0,
        indexed_line_count: 0,
        skipped_file_count: 0,
        error: Some(error),
    }
}

const DEFAULT_SEARCH_RESULT_LIMIT: usize = 100;
const MAX_SEARCH_RESULT_LIMIT: usize = 500;
const MAX_SEARCH_RESULT_OFFSET: usize = 10_000;
const MAX_SEARCH_QUERY_BYTES: usize = 1024;

async fn search_repository_contents(
    State(state): State<AppState>,
    headers: HeaderMap,
    Query(query): Query<SearchQuery>,
) -> Result<Json<SearchResponse>, StatusCode> {
    let (user_id, mut visible_repo_ids) = search_request_context(&state, &headers).await?;
    let search_mode = query.mode.unwrap_or_default();

    let trimmed_query = query.q.trim();
    if trimmed_query.is_empty() {
        return Err(StatusCode::BAD_REQUEST);
    }
    if query.q.len() > MAX_SEARCH_QUERY_BYTES || trimmed_query.len() > MAX_SEARCH_QUERY_BYTES {
        return Err(StatusCode::BAD_REQUEST);
    }
    let search_limit = query.limit.unwrap_or(DEFAULT_SEARCH_RESULT_LIMIT);
    if search_limit == 0 || search_limit > MAX_SEARCH_RESULT_LIMIT {
        return Err(StatusCode::BAD_REQUEST);
    }
    let search_offset = query.offset.unwrap_or(0);
    if search_offset > MAX_SEARCH_RESULT_OFFSET {
        return Err(StatusCode::BAD_REQUEST);
    }

    let requested_context_id = match query.context_id.as_deref().map(str::trim) {
        Some("") => return Err(StatusCode::NOT_FOUND),
        context_id => context_id,
    };
    if let Some(context_id) = requested_context_id {
        let organization_state = state
            .organization_store
            .organization_state()
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
        let search_context = organization_state
            .search_contexts
            .iter()
            .find(|search_context| {
                search_context.id == context_id && search_context.user_id == user_id
            })
            .ok_or(StatusCode::NOT_FOUND)?;
        let scoped_visible_repo_ids: HashSet<String> = search_context
            .repo_scope
            .iter()
            .filter(|repo_id| visible_repo_ids.contains(*repo_id))
            .cloned()
            .collect();
        if scoped_visible_repo_ids.is_empty() {
            return Err(StatusCode::NOT_FOUND);
        }
        visible_repo_ids = scoped_visible_repo_ids;
    }

    let requested_repo_id = match query.repo_id.as_deref().map(str::trim) {
        Some("") => return Err(StatusCode::NOT_FOUND),
        repo_id => repo_id,
    };
    if let Some(repo_id) = requested_repo_id {
        if !visible_repo_ids.contains(repo_id) {
            return Err(StatusCode::NOT_FOUND);
        }
    }

    let mut response = search_visible_authorized_repositories(
        &state,
        trimmed_query,
        requested_repo_id,
        search_mode,
        &visible_repo_ids,
    )?;

    if let Some(repo_id) = requested_repo_id {
        if response.results.is_empty() && !search_store_has_primary_index_status(&state, repo_id)? {
            if let Some(snapshot_response) = search_latest_local_sync_snapshot_for_repo(
                &state,
                trimmed_query,
                search_mode,
                &user_id,
                repo_id,
            )
            .await?
            {
                response = snapshot_response;
            }
        }
    } else {
        let repos_with_primary_results = response
            .results
            .iter()
            .map(|result| result.repo_id.as_str())
            .collect::<HashSet<_>>();
        let mut repo_ids_missing_primary_index = visible_repo_ids
            .iter()
            .filter(|repo_id| !repos_with_primary_results.contains(repo_id.as_str()))
            .filter_map(
                |repo_id| match search_store_has_primary_index_status(&state, repo_id) {
                    Ok(true) => None,
                    Ok(false) => Some(Ok(repo_id.clone())),
                    Err(error) => Some(Err(error)),
                },
            )
            .collect::<Result<Vec<_>, _>>()?;
        repo_ids_missing_primary_index.sort();

        for repo_id in repo_ids_missing_primary_index {
            if let Some(mut snapshot_response) = search_latest_local_sync_snapshot_for_repo(
                &state,
                trimmed_query,
                search_mode,
                &user_id,
                &repo_id,
            )
            .await?
            {
                response.results.append(&mut snapshot_response.results);
            }
        }
    }

    apply_search_pagination(&mut response, search_limit, search_offset);
    Ok(Json(response))
}

fn search_visible_authorized_repositories(
    state: &AppState,
    query: &str,
    requested_repo_id: Option<&str>,
    mode: SearchMode,
    visible_repo_ids: &HashSet<String>,
) -> Result<sourcebot_search::SearchResponse, StatusCode> {
    if let Some(repo_id) = requested_repo_id {
        let mut response = state
            .search
            .search_with_mode(query, Some(repo_id), mode)
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
        response
            .results
            .retain(|result| visible_repo_ids.contains(&result.repo_id));
        return Ok(response);
    }

    let mut repo_ids = visible_repo_ids.iter().cloned().collect::<Vec<_>>();
    repo_ids.sort();

    let mut results = Vec::new();
    for repo_id in repo_ids {
        let mut response = state
            .search
            .search_with_mode(query, Some(&repo_id), mode)
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
        response.results.retain(|result| {
            result.repo_id == repo_id && visible_repo_ids.contains(&result.repo_id)
        });
        results.append(&mut response.results);
    }

    Ok(sourcebot_search::SearchResponse::unpaginated_with_mode(
        query.to_string(),
        mode,
        None,
        results,
    ))
}

fn search_store_has_primary_index_status(
    state: &AppState,
    repo_id: &str,
) -> Result<bool, StatusCode> {
    state
        .search
        .repository_index_status(repo_id)
        .map(|status| status.is_some())
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)
}

fn apply_search_pagination(
    response: &mut sourcebot_search::SearchResponse,
    limit: usize,
    offset: usize,
) {
    let total_count = response.results.len();
    response.results = response
        .results
        .iter()
        .skip(offset)
        .take(limit)
        .cloned()
        .collect();
    response.pagination = SearchPagination {
        limit,
        offset,
        total_count,
        has_more: offset.saturating_add(limit) < total_count,
    };
}

async fn search_latest_local_sync_snapshot_for_repo(
    state: &AppState,
    query: &str,
    mode: SearchMode,
    user_id: &str,
    repo_id: &str,
) -> Result<Option<SearchResponse>, StatusCode> {
    let organization_state = state
        .organization_store
        .organization_state()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let authorized_organization_ids =
        authorized_organization_ids_for_repo(&organization_state, user_id, repo_id);
    if authorized_organization_ids.is_empty() {
        return Ok(None);
    }
    let Some(snapshot) =
        latest_local_sync_snapshot(&organization_state, repo_id, &authorized_organization_ids)
    else {
        return Ok(None);
    };

    match std::fs::symlink_metadata(&snapshot.search_index_artifact_path) {
        Ok(metadata) => {
            if !metadata.is_file() {
                return Err(StatusCode::INTERNAL_SERVER_ERROR);
            }
            return LocalSearchStore::from_index_artifact(
                repo_id,
                &snapshot.search_index_artifact_path,
            )
            .and_then(|search| search.search_with_mode(query, Some(repo_id), mode))
            .map(Some)
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR);
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
        Err(_) => return Err(StatusCode::INTERNAL_SERVER_ERROR),
    }

    if !snapshot.path.is_dir() {
        return Ok(None);
    }

    let snapshot_search =
        LocalSearchStore::new(HashMap::from([(repo_id.to_string(), snapshot.path)]));
    snapshot_search
        .search_with_mode(query, Some(repo_id), mode)
        .map(Some)
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)
}

fn authorized_organization_ids_for_repo(
    organization_state: &OrganizationState,
    user_id: &str,
    repo_id: &str,
) -> HashSet<String> {
    let member_organization_ids = organization_state
        .memberships
        .iter()
        .filter(|membership| membership.user_id == user_id)
        .map(|membership| membership.organization_id.as_str())
        .collect::<HashSet<_>>();

    organization_state
        .repo_permissions
        .iter()
        .filter(|binding| {
            binding.repository_id == repo_id
                && member_organization_ids.contains(binding.organization_id.as_str())
        })
        .map(|binding| binding.organization_id.clone())
        .collect()
}

struct LocalSyncSnapshot {
    repo_root: std::path::PathBuf,
    path: std::path::PathBuf,
    search_index_artifact_path: std::path::PathBuf,
    revision: String,
}

fn latest_local_sync_snapshot(
    organization_state: &OrganizationState,
    repo_id: &str,
    authorized_organization_ids: &HashSet<String>,
) -> Option<LocalSyncSnapshot> {
    if authorized_organization_ids.len() != 1 {
        return None;
    }

    let latest_successful_job = organization_state
        .repository_sync_jobs
        .iter()
        .filter(|job| {
            job.repository_id == repo_id
                && authorized_organization_ids.contains(&job.organization_id)
                && job.status == RepositorySyncJobStatus::Succeeded
                && job.synced_revision.is_some()
        })
        .max_by(|left, right| {
            left.finished_at
                .as_deref()
                .unwrap_or(left.queued_at.as_str())
                .cmp(
                    right
                        .finished_at
                        .as_deref()
                        .unwrap_or(right.queued_at.as_str()),
                )
                .then_with(|| left.queued_at.cmp(&right.queued_at))
                .then_with(|| left.id.cmp(&right.id))
        })?;
    let mut matching_connections = organization_state
        .connections
        .iter()
        .filter(|connection| connection.id == latest_successful_job.connection_id);
    let connection = matching_connections.next()?;
    if matching_connections.next().is_some() {
        return None;
    }
    let Some(ConnectionConfig::Local { repo_path }) = connection.config.as_ref() else {
        return None;
    };

    let job_artifact_root = std::path::Path::new(repo_path)
        .join(".sourcebot")
        .join("local-sync")
        .join(local_sync_artifact_path_component(
            &latest_successful_job.organization_id,
        ))
        .join(local_sync_artifact_path_component(
            &latest_successful_job.repository_id,
        ))
        .join(local_sync_artifact_path_component(
            &latest_successful_job.id,
        ));

    Some(LocalSyncSnapshot {
        repo_root: std::path::PathBuf::from(repo_path),
        path: job_artifact_root.join("snapshot"),
        search_index_artifact_path: job_artifact_root.join("search-index.json"),
        revision: latest_successful_job.synced_revision.clone()?,
    })
}

fn local_sync_artifact_path_component(component: &str) -> String {
    let sanitized = component
        .chars()
        .map(|character| match character {
            'a'..='z' | 'A'..='Z' | '0'..='9' | '_' | '-' => character,
            _ => '_',
        })
        .collect::<String>();
    if sanitized.is_empty() {
        "_".to_owned()
    } else {
        sanitized
    }
}

async fn create_ask_completion(
    State(state): State<AppState>,
    headers: HeaderMap,
    Json(request): Json<AskCompletionRequest>,
) -> Result<Json<AskCompletionResponse>, StatusCode> {
    let (ask_user_id, visible_repo_ids) = ask_request_context(&state, &headers).await?;
    let repo_ids = state
        .catalog
        .list_repositories()
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .into_iter()
        .map(|repository| repository.id)
        .collect::<Vec<_>>();
    let mut request = request.into_core_request(&repo_ids)?;
    if request
        .repo_scope
        .iter()
        .any(|repo_id| !visible_repo_ids.contains(repo_id))
    {
        return Err(StatusCode::NOT_FOUND);
    }
    let existing_thread = if let Some(thread_id) = request.thread_id.as_deref() {
        let existing_thread = state
            .ask_threads
            .get_thread_for_user(&ask_user_id, thread_id)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
            .ok_or(StatusCode::NOT_FOUND)?;
        if canonicalize_repo_scope(existing_thread.repo_scope.clone()) != request.repo_scope {
            return Err(StatusCode::NOT_FOUND);
        }
        request.previous_messages = existing_thread.messages.clone();
        Some(existing_thread)
    } else {
        None
    };

    let provider = build_llm_provider(LlmProviderConfig {
        provider: state
            .config
            .llm_provider
            .clone()
            .unwrap_or_else(|| "disabled".into()),
        model: state.config.llm_model.clone(),
        api_base: state.config.llm_api_base.clone(),
        api_key: state.config.llm_api_key.clone(),
    });
    let response = provider
        .complete(&request)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
    let filtered_citations =
        filter_ask_citations_to_repo_scope(&response.citations, &request.repo_scope);

    let (thread_id, session_id) = if let Some(existing_thread) = existing_thread {
        let thread_id = existing_thread.id.as_str();
        let timestamp = current_timestamp();
        state
            .ask_threads
            .append_message_for_user(
                &ask_user_id,
                thread_id,
                AskMessage {
                    id: next_ask_entity_id("msg"),
                    role: AskMessageRole::User,
                    content: request.prompt.clone(),
                    citations: Vec::new(),
                },
                &timestamp,
            )
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
            .ok_or(StatusCode::NOT_FOUND)?;
        state
            .ask_threads
            .append_message_for_user(
                &ask_user_id,
                thread_id,
                AskMessage {
                    id: next_ask_entity_id("msg"),
                    role: AskMessageRole::Assistant,
                    content: response.answer.clone(),
                    citations: filtered_citations.clone(),
                },
                &timestamp,
            )
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
            .ok_or(StatusCode::NOT_FOUND)?;
        (existing_thread.id, existing_thread.session_id)
    } else {
        let timestamp = current_timestamp();
        let thread = AskThread {
            id: next_ask_entity_id("thread"),
            session_id: next_ask_entity_id("session"),
            user_id: ask_user_id,
            title: ask_thread_title_from_prompt(&request.prompt),
            repo_scope: request.repo_scope.clone(),
            visibility: AskThreadVisibility::Private,
            created_at: timestamp.clone(),
            updated_at: timestamp,
            messages: vec![
                AskMessage {
                    id: next_ask_entity_id("msg"),
                    role: AskMessageRole::User,
                    content: request.prompt.clone(),
                    citations: Vec::new(),
                },
                AskMessage {
                    id: next_ask_entity_id("msg"),
                    role: AskMessageRole::Assistant,
                    content: response.answer.clone(),
                    citations: filtered_citations.clone(),
                },
            ],
        };
        let thread_id = thread.id.clone();
        let session_id = thread.session_id.clone();
        state
            .ask_threads
            .create_thread(thread)
            .await
            .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;
        (thread_id, session_id)
    };

    Ok(Json(AskCompletionResponse {
        provider: response.provider,
        model: response.model,
        answer: response.answer,
        citations: filtered_citations.clone(),
        rendered_citations: filtered_citations
            .iter()
            .map(|citation| citation.rendered())
            .collect(),
        thread_id,
        session_id,
    }))
}

fn ask_thread_visible_to_request(thread: &AskThread, visible_repo_ids: &HashSet<String>) -> bool {
    !thread.repo_scope.is_empty()
        && thread
            .repo_scope
            .iter()
            .all(|repo_id| visible_repo_ids.contains(repo_id))
}

fn ask_thread_summary_visible_to_request(
    thread: &AskThreadSummary,
    visible_repo_ids: &HashSet<String>,
) -> bool {
    !thread.repo_scope.is_empty()
        && thread
            .repo_scope
            .iter()
            .all(|repo_id| visible_repo_ids.contains(repo_id))
}

#[derive(Debug, Deserialize)]
struct AskThreadUpdateRequest {
    title: Option<String>,
    visibility: Option<String>,
}

fn parse_ask_thread_visibility(value: &str) -> Result<AskThreadVisibility, StatusCode> {
    match value.trim() {
        "private" => Ok(AskThreadVisibility::Private),
        "shared" => Ok(AskThreadVisibility::Shared),
        _ => Err(StatusCode::BAD_REQUEST),
    }
}

fn sanitize_ask_thread_response_citations(response: &mut AskThreadResponse) {
    for message in &mut response.messages {
        let filtered_citations =
            filter_ask_citations_to_repo_scope(&message.citations, &response.repo_scope);
        message.citations = filtered_citations.clone();
        message.rendered_citations = filtered_citations
            .iter()
            .map(|citation| citation.rendered())
            .collect();
        for citation in &mut message.rendered_citations {
            citation.display_label = format!("{}#{}", citation.path, citation.line_fragment);
        }
    }
}

async fn list_ask_threads(
    State(state): State<AppState>,
    headers: HeaderMap,
) -> Result<Json<Vec<AskThreadSummary>>, StatusCode> {
    let (ask_user_id, visible_repo_ids) = ask_request_context(&state, &headers).await?;
    let threads = state
        .ask_threads
        .list_threads_for_user(&ask_user_id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?;

    Ok(Json(
        threads
            .into_iter()
            .filter(|thread| ask_thread_summary_visible_to_request(thread, &visible_repo_ids))
            .collect(),
    ))
}

async fn get_ask_thread(
    State(state): State<AppState>,
    Path(thread_id): Path<String>,
    headers: HeaderMap,
) -> Result<Json<AskThreadResponse>, StatusCode> {
    let (ask_user_id, visible_repo_ids) = ask_request_context(&state, &headers).await?;
    let thread = state
        .ask_threads
        .get_thread_for_user(&ask_user_id, &thread_id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .filter(|thread| ask_thread_visible_to_request(thread, &visible_repo_ids))
        .ok_or(StatusCode::NOT_FOUND)?;
    let mut response = AskThreadResponse::from(thread);
    sanitize_ask_thread_response_citations(&mut response);

    Ok(Json(response))
}

async fn update_ask_thread(
    State(state): State<AppState>,
    Path(thread_id): Path<String>,
    headers: HeaderMap,
    Json(request): Json<AskThreadUpdateRequest>,
) -> Result<Json<AskThreadResponse>, StatusCode> {
    let (ask_user_id, visible_repo_ids) = ask_request_context(&state, &headers).await?;
    let existing_thread = state
        .ask_threads
        .get_thread_for_user(&ask_user_id, &thread_id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .filter(|thread| ask_thread_visible_to_request(thread, &visible_repo_ids))
        .ok_or(StatusCode::NOT_FOUND)?;

    let title = match request.title.as_deref() {
        Some(title) => {
            let trimmed = title.trim();
            if trimmed.is_empty() {
                return Err(StatusCode::BAD_REQUEST);
            }
            Some(trimmed.to_string())
        }
        None => None,
    };
    let visibility = request
        .visibility
        .as_deref()
        .map(parse_ask_thread_visibility)
        .transpose()?;
    if title.is_none() && visibility.is_none() {
        return Err(StatusCode::BAD_REQUEST);
    }

    let updated_at = current_timestamp();
    let updated_thread = state
        .ask_threads
        .update_thread_metadata_for_user(
            &ask_user_id,
            &existing_thread.id,
            title.as_deref(),
            visibility,
            &updated_at,
        )
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .filter(|thread| ask_thread_visible_to_request(thread, &visible_repo_ids))
        .ok_or(StatusCode::NOT_FOUND)?;
    let mut response = AskThreadResponse::from(updated_thread);
    sanitize_ask_thread_response_citations(&mut response);

    Ok(Json(response))
}

async fn delete_ask_thread(
    State(state): State<AppState>,
    Path(thread_id): Path<String>,
    headers: HeaderMap,
) -> Result<StatusCode, StatusCode> {
    let (ask_user_id, visible_repo_ids) = ask_request_context(&state, &headers).await?;
    let existing_thread = state
        .ask_threads
        .get_thread_for_user(&ask_user_id, &thread_id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .filter(|thread| ask_thread_visible_to_request(thread, &visible_repo_ids))
        .ok_or(StatusCode::NOT_FOUND)?;

    state
        .ask_threads
        .delete_thread_for_user(&ask_user_id, &existing_thread.id)
        .await
        .map_err(|_| StatusCode::INTERNAL_SERVER_ERROR)?
        .ok_or(StatusCode::NOT_FOUND)?;

    Ok(StatusCode::NO_CONTENT)
}

