    #[derive(Debug)]
    struct AlreadyInitializedBootstrapStore;

    #[derive(Debug)]
    struct FailingOrganizationStore {
        state: std::sync::Mutex<OrganizationState>,
        fail_reads: bool,
        fail_writes: bool,
    }

    impl FailingOrganizationStore {
        fn readable(state: OrganizationState, fail_writes: bool) -> Self {
            Self {
                state: std::sync::Mutex::new(state),
                fail_reads: false,
                fail_writes,
            }
        }

        fn unreadable(state: OrganizationState, fail_writes: bool) -> Self {
            Self {
                state: std::sync::Mutex::new(state),
                fail_reads: true,
                fail_writes,
            }
        }
    }

    #[derive(Debug)]
    struct CoordinatedOrganizationStore {
        state: std::sync::Mutex<OrganizationState>,
        initial_read_barrier: Arc<tokio::sync::Barrier>,
        initial_read_count: std::sync::atomic::AtomicUsize,
    }

    impl CoordinatedOrganizationStore {
        fn new(state: OrganizationState) -> Self {
            Self {
                state: std::sync::Mutex::new(state),
                initial_read_barrier: Arc::new(tokio::sync::Barrier::new(2)),
                initial_read_count: std::sync::atomic::AtomicUsize::new(0),
            }
        }
    }

    #[async_trait]
    impl OrganizationStore for FailingOrganizationStore {
        async fn organization_state(&self) -> anyhow::Result<OrganizationState> {
            if self.fail_reads {
                return Err(anyhow::anyhow!("organization-state read failed"));
            }

            Ok(self.state.lock().unwrap().clone())
        }

        async fn store_organization_state(&self, state: OrganizationState) -> anyhow::Result<()> {
            if self.fail_writes {
                return Err(anyhow::anyhow!("organization-state write failed"));
            }

            *self.state.lock().unwrap() = state;
            Ok(())
        }

        async fn store_repository_sync_job(
            &self,
            job: sourcebot_models::RepositorySyncJob,
        ) -> anyhow::Result<()> {
            if self.fail_reads {
                return Err(anyhow::anyhow!("organization-state read failed"));
            }

            if self.fail_writes {
                return Err(anyhow::anyhow!("organization-state write failed"));
            }

            let mut state = self.state.lock().unwrap();
            sourcebot_core::store_repository_sync_job(&mut state, job);
            Ok(())
        }

        async fn claim_next_repository_sync_job(
            &self,
            started_at: &str,
        ) -> anyhow::Result<Option<sourcebot_models::RepositorySyncJob>> {
            if self.fail_reads {
                return Err(anyhow::anyhow!("organization-state read failed"));
            }

            if self.fail_writes {
                return Err(anyhow::anyhow!("organization-state write failed"));
            }

            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::claim_next_repository_sync_job(
                &mut state, started_at,
            ))
        }

        async fn claim_next_review_agent_run(
            &self,
        ) -> anyhow::Result<Option<sourcebot_models::ReviewAgentRun>> {
            if self.fail_reads {
                return Err(anyhow::anyhow!("organization-state read failed"));
            }

            if self.fail_writes {
                return Err(anyhow::anyhow!("organization-state write failed"));
            }

            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::claim_next_review_agent_run(&mut state))
        }

        async fn complete_review_agent_run(
            &self,
            run_id: &str,
        ) -> anyhow::Result<Option<sourcebot_models::ReviewAgentRun>> {
            if self.fail_reads {
                return Err(anyhow::anyhow!("organization-state read failed"));
            }

            if self.fail_writes {
                return Err(anyhow::anyhow!("organization-state write failed"));
            }

            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::complete_review_agent_run(
                &mut state, run_id,
            ))
        }

        async fn fail_review_agent_run(
            &self,
            run_id: &str,
        ) -> anyhow::Result<Option<sourcebot_models::ReviewAgentRun>> {
            if self.fail_reads {
                return Err(anyhow::anyhow!("organization-state read failed"));
            }

            if self.fail_writes {
                return Err(anyhow::anyhow!("organization-state write failed"));
            }

            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::fail_review_agent_run(&mut state, run_id))
        }
    }

    #[async_trait]
    impl OrganizationStore for CoordinatedOrganizationStore {
        async fn organization_state(&self) -> anyhow::Result<OrganizationState> {
            let snapshot = self.state.lock().unwrap().clone();
            if self.initial_read_count.fetch_add(1, Ordering::SeqCst) < 2 {
                let _ = tokio::time::timeout(
                    std::time::Duration::from_millis(100),
                    self.initial_read_barrier.wait(),
                )
                .await;
            }

            Ok(snapshot)
        }

        async fn store_organization_state(&self, state: OrganizationState) -> anyhow::Result<()> {
            *self.state.lock().unwrap() = state;
            Ok(())
        }

        async fn store_repository_sync_job(
            &self,
            job: sourcebot_models::RepositorySyncJob,
        ) -> anyhow::Result<()> {
            let mut state = self.state.lock().unwrap();
            sourcebot_core::store_repository_sync_job(&mut state, job);
            Ok(())
        }

        async fn claim_next_repository_sync_job(
            &self,
            started_at: &str,
        ) -> anyhow::Result<Option<sourcebot_models::RepositorySyncJob>> {
            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::claim_next_repository_sync_job(
                &mut state, started_at,
            ))
        }

        async fn claim_next_review_agent_run(
            &self,
        ) -> anyhow::Result<Option<sourcebot_models::ReviewAgentRun>> {
            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::claim_next_review_agent_run(&mut state))
        }

        async fn complete_review_agent_run(
            &self,
            run_id: &str,
        ) -> anyhow::Result<Option<sourcebot_models::ReviewAgentRun>> {
            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::complete_review_agent_run(
                &mut state, run_id,
            ))
        }

        async fn fail_review_agent_run(
            &self,
            run_id: &str,
        ) -> anyhow::Result<Option<sourcebot_models::ReviewAgentRun>> {
            let mut state = self.state.lock().unwrap();
            Ok(sourcebot_core::fail_review_agent_run(&mut state, run_id))
        }
    }

    #[async_trait]
    impl BootstrapStore for AlreadyInitializedBootstrapStore {
        async fn bootstrap_status(&self) -> anyhow::Result<BootstrapStatus> {
            Ok(BootstrapStatus {
                bootstrap_required: true,
            })
        }

        async fn bootstrap_state(&self) -> anyhow::Result<Option<BootstrapState>> {
            Ok(None)
        }

        async fn initialize_bootstrap(&self, _state: BootstrapState) -> anyhow::Result<()> {
            Err(
                std::io::Error::new(ErrorKind::AlreadyExists, "bootstrap already initialized")
                    .into(),
            )
        }
    }

