    #[tokio::test]
    async fn logout_revokes_only_the_current_bearer_session() {
        let bootstrap_state_path = unique_test_path("logout-bootstrap");
        let local_session_state_path = unique_test_path("logout-sessions");
        let password = "correct horse battery staple";
        let password_hash = Argon2::default()
            .hash_password(password.as_bytes(), &SaltString::generate(&mut OsRng))
            .unwrap()
            .to_string();
        fs::write(
            &bootstrap_state_path,
            serde_json::to_vec(&BootstrapStateResponse {
                initialized_at: "2026-04-16T17:00:00Z".into(),
                admin_email: "admin@example.com".into(),
                admin_name: "Admin User".into(),
                password_hash,
            })
            .unwrap(),
        )
        .unwrap();

        let app = test_app_with_config(AppConfig {
            bootstrap_state_path: bootstrap_state_path.display().to_string(),
            local_session_state_path: local_session_state_path.display().to_string(),
            ..AppConfig::default()
        });

        let first_login_response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method("POST")
                    .uri("/api/v1/auth/login")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        serde_json::to_vec(&LoginRequest {
                            email: "admin@example.com".into(),
                            password: password.into(),
                        })
                        .unwrap(),
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(first_login_response.status(), StatusCode::CREATED);
        let first_login_payload: LoginResponseBody = read_json(first_login_response).await;

        let second_login_response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method("POST")
                    .uri("/api/v1/auth/login")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        serde_json::to_vec(&LoginRequest {
                            email: "admin@example.com".into(),
                            password: password.into(),
                        })
                        .unwrap(),
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(second_login_response.status(), StatusCode::CREATED);
        let second_login_payload: LoginResponseBody = read_json(second_login_response).await;

        let logout_response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method("POST")
                    .uri("/api/v1/auth/logout")
                    .header(
                        "authorization",
                        format!(
                            "Bearer {}:{}",
                            first_login_payload.session_id, first_login_payload.session_secret
                        ),
                    )
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();

        assert_eq!(logout_response.status(), StatusCode::NO_CONTENT);
        let logout_body = to_bytes(logout_response.into_body(), usize::MAX)
            .await
            .unwrap();
        assert!(logout_body.is_empty());

        let revoked_response = app
            .clone()
            .oneshot(
                Request::builder()
                    .uri("/api/v1/auth/me")
                    .header(
                        "authorization",
                        format!(
                            "Bearer {}:{}",
                            first_login_payload.session_id, first_login_payload.session_secret
                        ),
                    )
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(revoked_response.status(), StatusCode::UNAUTHORIZED);

        let retained_response = app
            .oneshot(
                Request::builder()
                    .uri("/api/v1/auth/me")
                    .header(
                        "authorization",
                        format!(
                            "Bearer {}:{}",
                            second_login_payload.session_id, second_login_payload.session_secret
                        ),
                    )
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(retained_response.status(), StatusCode::OK);

        fs::remove_file(bootstrap_state_path).unwrap();
        fs::remove_file(local_session_state_path).unwrap();
    }

    #[tokio::test]
    async fn logout_persists_audit_event_for_visible_organizations() {
        let organization_state_path = unique_test_path("logout-audit-orgs");
        let bootstrap_state_path = unique_test_path("logout-audit-bootstrap");
        let local_session_state_path = unique_test_path("logout-audit-sessions");
        let password = "correct horse battery staple";
        let password_hash = Argon2::default()
            .hash_password(password.as_bytes(), &SaltString::generate(&mut OsRng))
            .unwrap()
            .to_string();
        fs::write(
            &bootstrap_state_path,
            serde_json::to_vec(&BootstrapStateResponse {
                initialized_at: "2026-04-16T17:00:00Z".into(),
                admin_email: "admin@example.com".into(),
                admin_name: "Admin User".into(),
                password_hash,
            })
            .unwrap(),
        )
        .unwrap();
        fs::write(
            &organization_state_path,
            serde_json::to_vec(&OrganizationState {
                organizations: vec![
                    Organization {
                        id: "org_visible".into(),
                        slug: "visible".into(),
                        name: "Visible".into(),
                    },
                    Organization {
                        id: "org_hidden".into(),
                        slug: "hidden".into(),
                        name: "Hidden".into(),
                    },
                ],
                memberships: vec![OrganizationMembership {
                    organization_id: "org_visible".into(),
                    user_id: LOCAL_BOOTSTRAP_ADMIN_USER_ID.into(),
                    role: OrganizationRole::Viewer,
                    joined_at: "2026-04-21T00:00:00Z".into(),
                }],
                accounts: vec![LocalAccount {
                    id: LOCAL_BOOTSTRAP_ADMIN_USER_ID.into(),
                    email: "admin@example.com".into(),
                    name: "Admin User".into(),
                    password_hash: None,
                    created_at: "2026-04-20T23:55:00Z".into(),
                }],
                ..OrganizationState::default()
            })
            .unwrap(),
        )
        .unwrap();

        let app = test_app_with_config(AppConfig {
            organization_state_path: organization_state_path.display().to_string(),
            bootstrap_state_path: bootstrap_state_path.display().to_string(),
            local_session_state_path: local_session_state_path.display().to_string(),
            ..AppConfig::default()
        });

        let login_response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method("POST")
                    .uri("/api/v1/auth/login")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        serde_json::to_vec(&LoginRequest {
                            email: "admin@example.com".into(),
                            password: password.into(),
                        })
                        .unwrap(),
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(login_response.status(), StatusCode::CREATED);
        let login_payload: LoginResponseBody = read_json(login_response).await;

        let logout_response = app
            .oneshot(
                Request::builder()
                    .method("POST")
                    .uri("/api/v1/auth/logout")
                    .header(
                        "authorization",
                        format!(
                            "Bearer {}:{}",
                            login_payload.session_id, login_payload.session_secret
                        ),
                    )
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();

        assert_eq!(logout_response.status(), StatusCode::NO_CONTENT);
        let persisted: OrganizationState =
            serde_json::from_slice(&fs::read(&organization_state_path).unwrap()).unwrap();
        assert_eq!(persisted.audit_events.len(), 1);
        let audit_event = &persisted.audit_events[0];
        assert_eq!(audit_event.organization_id, "org_visible");
        assert_eq!(
            audit_event.actor.user_id.as_deref(),
            Some(LOCAL_BOOTSTRAP_ADMIN_USER_ID)
        );
        assert_eq!(audit_event.actor.api_key_id, None);
        assert_eq!(audit_event.action, "auth.logout");
        assert_eq!(audit_event.target_type, "session");
        assert_eq!(audit_event.target_id, login_payload.session_id);
        assert_eq!(audit_event.metadata, serde_json::json!({}));
        assert!(OffsetDateTime::parse(&audit_event.occurred_at, &Rfc3339).is_ok());

        fs::remove_file(organization_state_path).unwrap();
        fs::remove_file(bootstrap_state_path).unwrap();
        fs::remove_file(local_session_state_path).unwrap();
    }

